-- ENGINEER_WRITTEN 2024년 제1회 기출 복원 — 100문항 일괄 적재
-- mock_exam: kind=PAST_EXAM, visibility=PUBLISHED, expert_verified=0
--
-- 주의: subject 이름은 V33 과 정확히 일치해야 한다 ('정보시스템 구축 관리' — 가운데 공백).
-- 이전 V54 실행이 실패해 dangling mock_exam row 가 남았을 가능성이 있으므로
-- 재실행 안전성을 위해 동일 조합(ENGINEER_WRITTEN + PAST_EXAM + 2024년 1회)을 먼저 정리한다.

DELETE FROM mock_exam
 WHERE exam_type = 'ENGINEER_WRITTEN'
   AND kind = 'PAST_EXAM'
   AND exam_year = 2024
   AND exam_round = 1;

SET @seq := (SELECT COALESCE(MAX(sequence), 0) + 1 FROM mock_exam WHERE exam_type = 'ENGINEER_WRITTEN');

INSERT INTO mock_exam
  (name, exam_type, sequence, visibility, expert_verified,
   kind, exam_year, exam_round, exam_date, created_at, updated_at)
VALUES
  ('정보처리기사 필기 2024년 1회 복원', 'ENGINEER_WRITTEN', @seq, 'PUBLISHED', 0,
   'PAST_EXAM', 2024, 1, '2024-03-13', NOW(6), NOW(6));

SET @mock_exam_id := LAST_INSERT_ID();

INSERT INTO question
  (subject_id, content, question_type, correct_option, explanation,
   topic, difficulty, mock_exam_id, display_order,
   verification_category, content_hash, created_at, updated_at)
VALUES
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '사용자 요구사항 분석에 활용되는 가상의 인물로, 어떤 제품을 사용할 집단에 있는 다양한 사용자 유형을 대표하는 것은 무엇인가?\n\n① 스크럼 마스터\n② 페르소나\n③ 액션 빌더\n④ 액터', 'MCQ', 2, '정답: 2. 페르소나는 잠재 사용자 집단을 대표하는 가상의 사용자 모델이다.\n\n**오답 풀이**\n- 1번: 스크럼 마스터는 스크럼 팀이 스크럼을 잘 수행하도록 돕는 역할이다.\n- 2번: 페르소나는 사용자 유형을 대표하는 가상의 인물이다.\n- 3번: 액션 빌더는 액션 파일을 생성·편집하는 도구에 가깝다.\n- 4번: 액터는 시스템 기능을 사용하는 외부 대상이다.\n\n**보충 개념**\n페르소나는 사용자 요구사항을 분석할 때 실제 사용자의 목표, 행동, 불편함을 구체화하기 위해 활용된다.',
   '요구사항 분석', 1, @mock_exam_id, 1, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중, 바람직한 소프트웨어 설계의 기준과 가장 거리가 먼 것은 무엇인가?\n\n① 모듈의 효과적 제어를 위해 수평적으로 구성되어야 한다.\n② 절차와 자료 구조에 대해 명확하게 표현되어야 한다.\n③ 요구사항 명세서의 모든 내용을 구현해야 한다.\n④ 구현 및 테스트를 통해 결함과 기능 추적이 가능해야 한다.', 'MCQ', 1, '정답: 1. 소프트웨어 설계는 단순히 수평적으로 구성하는 것이 아니라 계층적이고 구조적으로 구성되어야 한다.\n\n**오답 풀이**\n- 1번: 모듈 제어를 위해 무조건 수평적으로 구성한다는 설명은 부적절하다.\n- 2번: 절차와 자료 구조를 명확히 표현하는 것은 좋은 설계 기준이다.\n- 3번: 요구사항 명세서의 내용을 구현 가능하게 반영해야 한다.\n- 4번: 결함과 기능 추적 가능성은 유지보수와 검증 측면에서 중요하다.\n\n**보충 개념**\n좋은 설계는 명확성, 모듈성, 추적성, 유지보수성을 만족해야 한다.',
   '소프트웨어 설계 원칙', 2, @mock_exam_id, 2, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '아래에서 설명하는 소프트웨어 설계 방식은 무엇인가?\n\n**<보기>**\n- 절차와 절차의 영향을 받는 데이터를 하나로 묶어서 설계하는 방식이다.\n- 설계 난이도가 높고 느린 편이지만 코드의 재활용성 및 유지보수가 용이하다.\n\n① 하향식 설계\n② 객체지향 설계\n③ 절차지향 설계\n④ 상향식 설계', 'MCQ', 2, '정답: 2. 데이터와 절차를 객체로 묶고 재사용성과 유지보수성을 높이는 방식은 객체지향 설계이다.\n\n**오답 풀이**\n- 1번: 하향식 설계는 상위 기능을 하위 기능으로 분해하는 방식이다.\n- 2번: 객체지향 설계는 데이터와 행위를 객체 단위로 묶어 설계한다.\n- 3번: 절차지향 설계는 처리 순서와 절차 중심의 설계 방식이다.\n- 4번: 상향식 설계는 하위 모듈을 먼저 설계하고 상위 모듈로 조립하는 방식이다.\n\n**보충 개념**\n객체지향 설계는 캡슐화, 상속, 다형성 등을 통해 변경에 강한 구조를 만들 수 있다.',
   '객체지향 설계', 2, @mock_exam_id, 3, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중, 소프트웨어 품질 특성 표준(ISO/IEC 25010)에 해당하지 않는 것은 무엇인가?\n\n① 기능성\n② 효율성\n③ 종속성\n④ 사용성', 'MCQ', 3, '정답: 3. ISO/IEC 25010의 품질 특성에 종속성은 포함되지 않는다.\n\n**오답 풀이**\n- 1번: 기능성은 소프트웨어 품질 특성에 해당한다.\n- 2번: 효율성은 자원 사용과 성능 관련 품질 특성이다.\n- 3번: 종속성은 ISO/IEC 25010의 대표 품질 특성이 아니다.\n- 4번: 사용성은 사용자가 소프트웨어를 쉽게 사용할 수 있는 정도를 의미한다.\n\n**보충 개념**\nISO/IEC 25010은 기능 적합성, 성능 효율성, 호환성, 사용성, 신뢰성, 보안성, 유지보수성, 이식성 등을 품질 특성으로 다룬다.',
   'ISO/IEC 25010', 1, @mock_exam_id, 4, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중, 컴포넌트에 대한 설명과 가장 거리가 먼 것은 무엇인가?\n\n① 재사용이 가능한 독립적인 소프트웨어 단위이다.\n② 애플리케이션 개발을 위한 기반 구조를 제공한다.\n③ UI 요소, DB 연결, 비즈니스 로직 등 다양한 형태를 가진다.\n④ 다른 컴포넌트와 조합하여 더 복잡한 시스템 구축이 가능하다.', 'MCQ', 2, '정답: 2. 애플리케이션 개발의 기반 구조를 제공하는 것은 프레임워크에 더 가깝다.\n\n**오답 풀이**\n- 1번: 컴포넌트는 재사용 가능한 독립 소프트웨어 단위이다.\n- 2번: 기반 구조를 제공하는 것은 컴포넌트보다 프레임워크 설명에 가깝다.\n- 3번: 컴포넌트는 UI, DB 연결, 비즈니스 로직 등 다양한 형태로 구현될 수 있다.\n- 4번: 컴포넌트는 조합을 통해 더 큰 시스템을 구성할 수 있다.\n\n**보충 개념**\n컴포넌트 기반 개발은 재사용 가능한 단위를 조립해 시스템을 만드는 방식이다.',
   '컴포넌트', 2, @mock_exam_id, 5, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중, UI 설계에 대한 설명과 가장 거리가 먼 것은 무엇인가?\n\n① 별다른 이해의 노력 없이 즉시 사용 가능해야 한다.\n② 사용자의 목적을 정확하게 달성시킬 수 있어야 한다.\n③ 누구나 쉽게 배우고 익힐 수 있어야 한다.\n④ 시스템 요구사항을 수용하고 오류를 최소화해야 한다.', 'MCQ', 4, '정답: 4. UI 설계는 시스템 요구사항보다 사용자 요구사항을 중심으로 수용해야 한다.\n\n**오답 풀이**\n- 1번: 직관성은 UI 설계의 중요한 원칙이다.\n- 2번: 유효성은 사용자의 목적 달성을 지원하는 성질이다.\n- 3번: 학습 용이성은 좋은 UI의 기준이다.\n- 4번: UI 설계는 시스템 요구사항이 아니라 사용자 요구사항 수용이 핵심이다.\n\n**보충 개념**\nUI 설계 원칙에는 직관성, 유효성, 학습성, 유연성 등이 있다.',
   'UI 설계', 2, @mock_exam_id, 6, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'LOC 기법에서 사용하는 예측치 요소가 아닌 것은?\n\n① 측정치\n② 기대치\n③ 낙관치\n④ 비관치', 'MCQ', 1, '정답: 1. LOC 예측에는 낙관치, 기대치, 비관치를 사용하며 측정치는 예측치 요소가 아니다.\n\n**오답 풀이**\n- 1번: 측정치는 LOC 예측 공식의 구성 요소가 아니다.\n- 2번: 기대치는 LOC 예측 공식에 사용된다.\n- 3번: 낙관치는 가장 적게 예상되는 규모이다.\n- 4번: 비관치는 가장 크게 예상되는 규모이다.\n\n**보충 개념**\nLOC 예측치는 일반적으로 (낙관치 + 4×기대치 + 비관치) / 6으로 산정한다.',
   'LOC', 1, @mock_exam_id, 7, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중, 아래에서 설명하는 소프트웨어 개발 모델은 무엇인가?\n\n**<보기>**\n- 단계별로 결과물이 명확하게 산출되어야 다음 단계로 넘어가는 방식이다.\n- 제품의 기능 보완이 불가능하므로 매뉴얼 작성이 필수적이다.\n\n① 프로토타입 모델\n② 폭포수 모델\n③ 나선형 모델\n④ 스크럼 모델', 'MCQ', 2, '정답: 2. 단계별 산출물을 확정하고 순차적으로 진행하는 모델은 폭포수 모델이다.\n\n**오답 풀이**\n- 1번: 프로토타입 모델은 시제품을 통해 요구사항을 구체화한다.\n- 2번: 폭포수 모델은 이전 단계가 완료되어야 다음 단계로 진행한다.\n- 3번: 나선형 모델은 위험 분석을 포함해 반복적으로 개발한다.\n- 4번: 스크럼 모델은 스프린트 단위로 반복 개발하는 애자일 모델이다.\n\n**보충 개념**\n폭포수 모델은 요구사항 변경에 취약하지만 단계별 문서화와 관리가 명확하다.',
   '폭포수 모델', 2, @mock_exam_id, 8, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중, 애자일 프로세스에 대한 설명으로 옳지 않은 것은?\n\n① 소프트웨어를 사용할 고객과의 소통에 중심을 둔다.\n② Scrum, XP 모델과 달리 고객의 피드백을 긴 주기로 반영한다.\n③ 절차, 문서보다는 소통과 협업에 가치를 둔다.\n④ 계획의 수행보다 변화에 대응하는 것에 가치를 둔다.', 'MCQ', 2, '정답: 2. 애자일은 고객 피드백을 짧은 주기로 자주 반영한다.\n\n**오답 풀이**\n- 1번: 애자일은 고객과의 소통을 중시한다.\n- 2번: 고객 피드백을 긴 주기로 반영한다는 설명은 애자일과 거리가 멀다.\n- 3번: 애자일은 문서보다 협업과 동작하는 소프트웨어를 중시한다.\n- 4번: 애자일은 계획 고수보다 변화 대응을 중시한다.\n\n**보충 개념**\nScrum과 XP는 대표적인 애자일 개발 방법론이다.',
   '애자일', 2, @mock_exam_id, 9, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '좋은 SW 설계를 위한 방침으로 옳은 것은?\n\n① 응집도와 결합도는 모두 높여야 한다.\n② 응집도는 높이고, 결합도는 낮추어야 한다.\n③ 응집도는 낮추고, 결합도는 높여야 한다.\n④ 응집도와 결합도를 모두 낮춰야 한다.', 'MCQ', 2, '정답: 2. 좋은 설계는 모듈 내부 관련성인 응집도를 높이고, 모듈 간 의존성인 결합도를 낮춰야 한다.\n\n**오답 풀이**\n- 1번: 결합도는 낮을수록 좋다.\n- 2번: 응집도는 높고 결합도는 낮은 구조가 바람직하다.\n- 3번: 응집도가 낮고 결합도가 높은 구조는 유지보수성이 떨어진다.\n- 4번: 응집도는 낮추는 것이 아니라 높여야 한다.\n\n**보충 개념**\n높은 응집도와 낮은 결합도는 변경 영향 범위를 줄이고 재사용성을 높인다.',
   '응집도와 결합도', 1, @mock_exam_id, 10, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'COCOMO 모델 중, 30만 라인 이하의 OS, DBMS, 트랜잭션 처리 시스템 등에 적용되는 산정 기법은 무엇인가?\n\n① Organic\n② Embedded\n③ Detached\n④ Semi-Detached', 'MCQ', 4, '정답: 4. 30만 라인 이하의 중간 규모 시스템에는 Semi-Detached 모드가 적용된다.\n\n**오답 풀이**\n- 1번: Organic은 비교적 단순하고 소규모인 5만 라인 이하 프로젝트에 적용된다.\n- 2번: Embedded는 복잡하고 제약이 큰 30만 라인 이상의 시스템에 적용된다.\n- 3번: Detached는 COCOMO의 대표 모드 명칭으로 사용되지 않는다.\n- 4번: Semi-Detached는 중간 규모 프로젝트에 적용된다.\n\n**보충 개념**\nCOCOMO는 소프트웨어 규모를 기반으로 비용과 노력을 산정하는 모델이다.',
   'COCOMO', 2, @mock_exam_id, 11, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중, XP에 대한 설명으로 옳은 것은 무엇인가?\n\n① 제품 책임자와 스크럼 마스터, 개발팀으로 구성된다.\n② 사용자 스토리에 따라 스파이크 또는 이터레이션을 진행한다.\n③ 반복적인 스프린트를 통해 제품을 완성시켜 나간다.\n④ 짧은 시간 동안 소멸차트를 통해 진행 상황을 점검한다.', 'MCQ', 2, '정답: 2. XP는 사용자 스토리를 기반으로 이터레이션을 진행하며 필요 시 스파이크를 수행한다.\n\n**오답 풀이**\n- 1번: 제품 책임자, 스크럼 마스터, 개발팀은 Scrum의 구성이다.\n- 2번: 사용자 스토리와 이터레이션은 XP의 특징이다.\n- 3번: 스프린트는 Scrum에서 주로 사용하는 반복 주기 용어이다.\n- 4번: 소멸차트는 Scrum의 진행 관리 도구로 많이 사용된다.\n\n**보충 개념**\nXP는 의사소통, 단순성, 피드백, 용기, 존중을 핵심 가치로 둔다.',
   'XP', 2, @mock_exam_id, 12, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'HIPO 다이어그램에 해당하지 않는 것은 무엇인가?\n\n① 가시적 도표\n② 세부적 도표\n③ 총체적 도표\n④ 순차적 도표', 'MCQ', 4, '정답: 4. HIPO 다이어그램의 종류에는 가시적 도표, 총체적 도표, 세부적 도표가 있으며 순차적 도표는 해당하지 않는다.\n\n**오답 풀이**\n- 1번: 가시적 도표는 시스템 전체 기능 구조를 보여준다.\n- 2번: 세부적 도표는 기능의 상세 내용을 기술한다.\n- 3번: 총체적 도표는 입력, 처리, 출력의 전반 정보를 제공한다.\n- 4번: 순차적 도표는 HIPO의 종류가 아니다.\n\n**보충 개념**\nHIPO는 시스템 기능을 계층적으로 표현하고 입력·처리·출력을 명확히 나타내는 문서화 기법이다.',
   'HIPO', 1, @mock_exam_id, 13, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'NS 차트의 구성요소가 아닌 것은 무엇인가?\n\n① 순차\n② 이동\n③ 선택\n④ 반복', 'MCQ', 2, '정답: 2. NS 차트는 순차, 선택, 반복 구조를 표현하며 이동은 구성요소가 아니다.\n\n**오답 풀이**\n- 1번: 순차는 NS 차트의 기본 제어 구조이다.\n- 2번: 이동은 NS 차트의 기본 구성요소가 아니다.\n- 3번: 선택은 조건 분기를 표현한다.\n- 4번: 반복은 반복 제어 구조를 표현한다.\n\n**보충 개념**\nNS 차트는 구조적 프로그래밍의 제어 구조를 도식화하는 방법이다.',
   'NS 차트', 1, @mock_exam_id, 14, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'CASE 도구의 원천 기술이 아닌 것은 무엇인가?\n\n① 구조적 기법\n② 기술 지원\n③ 자동 프로그래밍\n④ 분산 처리', 'MCQ', 2, '정답: 2. CASE 도구의 원천 기술에는 구조적 기법, 프로토타이핑, 자동 프로그래밍, 정보 저장소, 분산 처리 등이 있으며 기술 지원은 해당하지 않는다.\n\n**오답 풀이**\n- 1번: 구조적 기법은 CASE의 원천 기술이다.\n- 2번: 기술 지원은 CASE의 원천 기술 명칭으로 보기 어렵다.\n- 3번: 자동 프로그래밍은 CASE 원천 기술 중 하나이다.\n- 4번: 분산 처리는 CASE 원천 기술에 포함된다.\n\n**보충 개념**\nCASE는 소프트웨어 개발 과정을 자동화하고 지원하는 도구를 의미한다.',
   'CASE', 2, @mock_exam_id, 15, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '소프트웨어 품질을 평가하기 위한 국제 표준 문서 및 모델을 의미하는 것은 무엇인가?\n\n① ISO/IEC 25010\n② ISO/IEC 29119\n③ ISO/IEC 12207\n④ ISO/IEC 12119', 'MCQ', 1, '정답: 1. ISO/IEC 25010은 소프트웨어 제품 품질 모델을 정의한 국제 표준이다.\n\n**오답 풀이**\n- 1번: ISO/IEC 25010은 소프트웨어 품질 특성 모델이다.\n- 2번: ISO/IEC 29119는 소프트웨어 테스트 관련 표준이다.\n- 3번: ISO/IEC 12207은 소프트웨어 생명주기 프로세스 표준이다.\n- 4번: ISO/IEC 12119는 패키지 소프트웨어 품질 요구와 테스트 관련 표준이다.\n\n**보충 개념**\nISO/IEC 25010은 기존 품질 모델을 발전시켜 보안성, 호환성 등 품질 특성을 체계화한다.',
   '소프트웨어 품질 표준', 2, @mock_exam_id, 16, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중, 밀접도가 가장 낮은 응집도는 무엇인가?\n\n① Procedural\n② Functional\n③ Coincidental\n④ Sequential', 'MCQ', 3, '정답: 3. 우연적 응집도(Coincidental)는 모듈 내부 요소 간 관련성이 가장 낮은 응집도이다.\n\n**오답 풀이**\n- 1번: 절차적 응집도는 관련 기능들이 순서에 따라 수행되는 경우이다.\n- 2번: 기능적 응집도는 가장 강한 응집도이다.\n- 3번: 우연적 응집도는 관련 없는 요소들이 모인 가장 약한 응집도이다.\n- 4번: 순차적 응집도는 한 기능의 출력이 다음 기능의 입력으로 사용되는 경우이다.\n\n**보충 개념**\n응집도는 기능적 응집도가 가장 높고 우연적 응집도가 가장 낮다.',
   '응집도', 2, @mock_exam_id, 17, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중, 다이어그램의 종류가 나머지 셋과 다른 하나는 무엇인가?\n\n① 활동 다이어그램\n② 상호작용 다이어그램\n③ 유스케이스 다이어그램\n④ 클래스 다이어그램', 'MCQ', 4, '정답: 4. 클래스 다이어그램은 구조적 다이어그램이고, 나머지는 행위적 다이어그램에 속한다.\n\n**오답 풀이**\n- 1번: 활동 다이어그램은 행위적 다이어그램이다.\n- 2번: 상호작용 다이어그램은 행위적 다이어그램 계열이다.\n- 3번: 유스케이스 다이어그램은 행위적 다이어그램이다.\n- 4번: 클래스 다이어그램은 구조적 다이어그램이다.\n\n**보충 개념**\nUML 다이어그램은 크게 구조적 다이어그램과 행위적 다이어그램으로 구분된다.',
   'UML 다이어그램', 2, @mock_exam_id, 18, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), '다음 중, UML의 연관 관계에 대한 설명과 거리가 먼 것은?\n\n① 둘 이상의 사물이 서로 관련되어 있음을 나타낸다.\n② 사물이 다른 사물에 포함되어 있는 관계를 표현한다.\n③ 방향성을 실선 화살표로 표현한다.\n④ 사물이 서로 참조하는 경우에는 실선으로만 표현한다.', 'MCQ', 2, '정답: 2. 사물이 다른 사물에 포함되는 관계는 연관 관계가 아니라 집합 또는 포함 관계에 가깝다.\n\n**오답 풀이**\n- 1번: 연관 관계는 둘 이상의 사물이 관련됨을 나타낸다.\n- 2번: 포함 관계 설명으로, 연관 관계의 일반 설명과 거리가 있다.\n- 3번: 방향성이 있는 연관은 실선 화살표로 표현할 수 있다.\n- 4번: 양방향 참조는 방향 화살표 없이 실선으로 표현할 수 있다.\n\n**보충 개념**\nUML 관계에는 연관, 의존, 일반화, 실체화, 집합, 포함 등이 있다.',
   'UML 관계', 2, @mock_exam_id, 19, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 설계' ORDER BY id LIMIT 1), 'LOC 기법에 대한 설명으로 옳지 않은 것은?\n\n① 낙관치, 기대치, 비관치를 이용하여 예측치를 산정한다.\n② 노력과 월평균 인건비를 통해 개발 비용을 산정한다.\n③ 하향식 비용 산정 기법에 해당한다.\n④ 개발 기간, 생산성, 노력 등을 계산할 수 있다.', 'MCQ', 3, '정답: 3. LOC 기법은 하향식이 아니라 상향식 비용 산정 기법에 해당한다.\n\n**오답 풀이**\n- 1번: LOC는 낙관치, 기대치, 비관치를 이용해 예측치를 산정한다.\n- 2번: 노력과 인건비를 이용해 개발 비용을 산정할 수 있다.\n- 3번: LOC는 상향식 비용 산정 기법이다.\n- 4번: LOC를 바탕으로 개발 기간, 생산성, 노력 등을 계산할 수 있다.\n\n**보충 개념**\n상향식 산정은 세부 기능 단위의 규모와 비용을 산정한 뒤 전체 비용을 합산하는 방식이다.',
   'LOC', 2, @mock_exam_id, 20, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '아래에서 설명하는 알고리즘 설계 기법은 무엇인가?\n\n**<보기>**\n- 어떤 문제를 해결하기 위해 그 문제를 더 작은 문제의 연장선으로 생각하는 방식이다.\n- 작은 문제의 풀이를 활용하여 큰 문제의 풀이를 찾는 Bottom-Up 방식이다.\n\n① 동적 계획법\n② 재귀적 알고리즘\n③ 근사 알고리즘\n④ 분할 정복법', 'MCQ', 1, '정답: 1. 작은 문제의 해를 저장하고 활용해 큰 문제를 해결하는 방식은 동적 계획법이다.\n\n**오답 풀이**\n- 1번: 동적 계획법은 부분 문제의 해를 이용해 전체 문제를 해결한다.\n- 2번: 재귀적 알고리즘은 함수가 자기 자신을 호출하는 방식이다.\n- 3번: 근사 알고리즘은 최적해 대신 근사해를 구하는 방식이다.\n- 4번: 분할 정복법은 문제를 독립적인 작은 문제로 나누어 해결한다.\n\n**보충 개념**\n동적 계획법은 중복 부분 문제와 최적 부분 구조가 있을 때 효과적이다.',
   '동적 계획법', 2, @mock_exam_id, 21, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '아래 트리를 In-Order 방식으로 운행할 경우 올바른 순서는 무엇인가?\n\n**<트리 구조>**\n- 루트 노드는 F이다.\n- F의 왼쪽 자식은 A이다.\n- A의 왼쪽 자식은 B, 오른쪽 자식은 C이다.\n- B의 왼쪽 자식은 D이다.\n- C의 왼쪽 자식은 E이다.\n- E의 왼쪽 자식은 G, 오른쪽 자식은 H이다.\n\n**<조건>**\n중위 순회는 왼쪽 서브트리 → 루트 → 오른쪽 서브트리 순서로 방문한다.\n\n① A B D C E G H F\n② D B A G E H C F\n③ D B G H E F C A\n④ A B C D E F G H', 'MCQ', 2, '정답: 2. 중위 순회는 왼쪽 서브트리 → 루트 → 오른쪽 서브트리 순서로 방문한다. 제시된 트리를 중위 순회하면 D → B → A → G → E → H → C → F가 된다.\n\n**오답 풀이**\n- 1번: B의 왼쪽 자식 D를 B보다 먼저 방문하지 않았다.\n- 2번: 주어진 트리의 중위 순회 결과이다.\n- 3번: A와 F의 방문 위치가 중위 순회와 맞지 않는다.\n- 4번: 단순 알파벳 순서에 가깝고 중위 순회 결과가 아니다.\n\n**보충 개념**\n이진 트리의 중위 순회는 Left → Root → Right 순서이다. 서브트리마다 같은 규칙을 재귀적으로 적용한다.',
   '트리 순회', 3, @mock_exam_id, 22, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중, 해시 함수의 종류에 해당하지 않는 것은 무엇인가?\n\n① 제산법\n② 폴딩법\n③ 난수 변환법\n④ 무작위법', 'MCQ', 3, '정답: 3. 해시 함수에는 제산법, 폴딩법, 무작위법 등이 있으며 난수 변환법은 일반적인 해시 함수 종류로 보기 어렵다.\n\n**오답 풀이**\n- 1번: 제산법은 키를 해시 테이블 크기로 나눈 나머지를 이용한다.\n- 2번: 폴딩법은 키를 여러 부분으로 나누어 결합한다.\n- 3번: 난수 변환법은 표준적인 해시 함수 분류에 해당하지 않는다.\n- 4번: 무작위법은 난수를 이용해 홈 주소를 구하는 방식이다.\n\n**보충 개념**\n대표 해시 함수에는 제산법, 제곱법, 폴딩법, 기수 변환법, 무작위법 등이 있다.',
   '해시 함수', 2, @mock_exam_id, 23, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중, 인터페이스 구현 검증 지원 도구가 아닌 것은 무엇인가?\n\n① STAF\n② NTAF\n③ FitNesse\n④ JTAF', 'MCQ', 4, '정답: 4. JTAF는 대표적인 인터페이스 구현 검증 지원 도구로 분류되지 않는다.\n\n**오답 풀이**\n- 1번: STAF는 테스트 자동화 프레임워크이다.\n- 2번: NTAF는 FitNesse와 STAF의 장점을 결합한 테스트 자동화 프레임워크이다.\n- 3번: FitNesse는 웹 기반 테스트 케이스 설계와 실행을 지원한다.\n- 4번: JTAF는 대표 검증 도구 목록에 포함되지 않는다.\n\n**보충 개념**\n인터페이스 구현 검증 도구에는 xUnit, STAF, FitNesse, NTAF, Selenium 등이 있다.',
   '인터페이스 검증 도구', 2, @mock_exam_id, 24, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중, 디지털 저작권 관리(DRM) 기술에 대한 설명과 가장 거리가 먼 것은 무엇인가?\n\n① 사용자에게 배포되는 소프트웨어이므로 반드시 내부 콘텐츠에 대한 암호화 및 보안을 고려해야 한다.\n② 디지털 저작물에 대한 배타적/독점적 권리로 타인의 침해를 받지 않을 고유한 권한이다.\n③ 복제가 어려운 디지털 저작물에 대해 불법 복제 및 배포 등을 막기 위한 절차적인 방법을 말한다.\n④ 콘텐츠 식별, 정책, 암호화, 인증 등의 기술을 바탕으로 저작물의 신뢰도를 향상시킨다.', 'MCQ', 3, '정답: 3. 디지털 저작물은 일반적으로 복제가 쉬우므로, 복제가 어려운 저작물이라는 설명은 부적절하다.\n\n**오답 풀이**\n- 1번: DRM은 콘텐츠 보호를 위해 암호화와 보안을 고려한다.\n- 2번: 저작권은 저작물에 대한 배타적 권리를 의미한다.\n- 3번: 디지털 저작물은 복제가 쉽기 때문에 DRM이 필요하다.\n- 4번: DRM은 콘텐츠 식별, 정책, 암호화, 인증 등과 관련된다.\n\n**보충 개념**\nDRM은 디지털 콘텐츠의 불법 복제, 배포, 사용을 통제하기 위한 기술과 절차를 포함한다.',
   'DRM', 2, @mock_exam_id, 25, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '정형 기술 검토(FTR)의 원칙이 아닌 것은 무엇인가?\n\n① 제품의 검토에만 집중한다.\n② 논쟁과 반박을 제한한다.\n③ 참가자의 수를 확대한다.\n④ 해결책에 대해서 논하지 않는다.', 'MCQ', 3, '정답: 3. FTR은 효율적인 검토를 위해 참가자 수를 제한하는 것이 원칙이다.\n\n**오답 풀이**\n- 1번: FTR은 사람보다 제품 자체의 검토에 집중한다.\n- 2번: 논쟁과 반박을 제한하고 검토 목적에 집중한다.\n- 3번: 참가자 수를 확대하는 것은 FTR 원칙이 아니다.\n- 4번: 검토 회의에서는 문제 발견에 집중하고 해결책 논의는 제한한다.\n\n**보충 개념**\nFTR은 소프트웨어 산출물의 오류를 조기에 발견하기 위한 공식 검토 기법이다.',
   'FTR', 2, @mock_exam_id, 26, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), 'V-모델 중 인수 테스트에 대한 설명으로 옳지 않은 것은?\n\n① 사용자 요구사항 충족 여부를 사용자가 직접 테스트하는 것이다.\n② 알파 테스트는 개발자의 장소에서 테스트를 진행한다.\n③ 베타 테스트는 제한되지 않은 환경에서 테스트를 진행한다.\n④ 모듈의 기능 수행 여부와 논리적인 오류를 검출하는 과정이다.', 'MCQ', 4, '정답: 4. 모듈의 기능 수행 여부와 논리적 오류를 검출하는 것은 단위 테스트에 해당한다.\n\n**오답 풀이**\n- 1번: 인수 테스트는 사용자 요구사항 충족 여부를 확인한다.\n- 2번: 알파 테스트는 개발자 환경에서 사용자가 테스트한다.\n- 3번: 베타 테스트는 실제 사용 환경에 가까운 제한되지 않은 환경에서 수행된다.\n- 4번: 모듈 단위 오류 검출은 단위 테스트 설명이다.\n\n**보충 개념**\nV-모델의 테스트 단계는 단위, 통합, 시스템, 인수 테스트로 이어진다.',
   '인수 테스트', 2, @mock_exam_id, 27, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중, 단위 테스트 도구가 아닌 것은 무엇인가?\n\n① CppUnit\n② RowUnit\n③ JUnit\n④ HttpUnit', 'MCQ', 2, '정답: 2. RowUnit은 대표적인 단위 테스트 도구로 분류되지 않는다.\n\n**오답 풀이**\n- 1번: CppUnit은 C++용 단위 테스트 도구이다.\n- 2번: RowUnit은 일반적인 단위 테스트 도구 목록에 해당하지 않는다.\n- 3번: JUnit은 Java용 단위 테스트 프레임워크이다.\n- 4번: HttpUnit은 웹 사이트 테스트를 위한 오픈소스 테스트 프레임워크이다.\n\n**보충 개념**\nxUnit 계열 도구는 다양한 언어에서 단위 테스트를 지원한다.',
   '단위 테스트 도구', 1, @mock_exam_id, 28, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '문자열 “ABCDEFGHIJKLMN”에서 이진 탐색 기법을 사용하여 “E”를 찾는 경우, 실제 비교 횟수는 얼마인가?\n\n① 3\n② 4\n③ 5\n④ 6', 'MCQ', 1, '정답: 1. 중간값을 기준으로 비교하면 G, C, E 순서로 비교하므로 총 3회이다.\n\n**오답 풀이**\n- 1번: 실제 비교 횟수는 G → C → E로 3회이다.\n- 2번: 4회까지 비교하기 전에 E를 찾는다.\n- 3번: 5회는 필요하지 않다.\n- 4번: 6회는 선형 탐색에 가까운 횟수이다.\n\n**보충 개념**\n이진 탐색은 정렬된 데이터에서 중간값과 비교하며 탐색 범위를 절반씩 줄인다.',
   '이진 탐색', 2, @mock_exam_id, 29, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '입력 데이터 간의 관계와 출력에 미치는 영향을 분석하여 테스트 케이스를 설계하여 테스트를 진행하는 기법으로 옳은 것은?\n\n① Boundary Value Analysis\n② Equivalence Partitioning\n③ Cause-Effect Graphing\n④ Error Guessing', 'MCQ', 3, '정답: 3. 입력 조건과 출력 결과 사이의 인과 관계를 분석하는 기법은 원인-효과 그래프 검사이다.\n\n**오답 풀이**\n- 1번: 경계값 분석은 입력 조건의 경계값을 중심으로 테스트한다.\n- 2번: 동치 분할은 입력값을 동등한 그룹으로 나누어 테스트한다.\n- 3번: 원인-효과 그래프는 입력과 출력의 관계를 분석한다.\n- 4번: 오류 예측은 경험을 바탕으로 오류 가능성을 예측해 테스트한다.\n\n**보충 개념**\n원인-효과 그래프 검사는 복합 조건이 출력에 미치는 영향을 체계적으로 분석할 때 유용하다.',
   '블랙박스 테스트', 2, @mock_exam_id, 30, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '테스트 진행을 위한 입력값, 실행 조건, 기대 결과 등의 집합을 의미하는 테스트 관련 용어는 무엇인가?\n\n① 테스트 스크립트\n② 테스트 스위트\n③ 테스트 케이스\n④ 테스트 드라이버', 'MCQ', 3, '정답: 3. 입력값, 실행 조건, 기대 결과로 구성된 테스트 항목은 테스트 케이스이다.\n\n**오답 풀이**\n- 1번: 테스트 스크립트는 자동화된 테스트 실행 절차이다.\n- 2번: 테스트 스위트는 테스트 케이스의 집합이다.\n- 3번: 테스트 케이스는 입력값, 조건, 기대 결과를 포함한다.\n- 4번: 테스트 드라이버는 하위 모듈 테스트를 돕는 보조 모듈이다.\n\n**보충 개념**\n테스트 케이스는 요구사항을 검증하기 위한 가장 기본적인 테스트 산출물이다.',
   '테스트 케이스', 1, @mock_exam_id, 31, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), 'V-모델에 의한 테스트 수행 절차를 올바르게 나열한 것은?\n\n① 단위 테스트-통합 테스트-시스템 테스트-인수 테스트\n② 단위 테스트-인수 테스트-통합 테스트-시스템 테스트\n③ 단위 테스트-시스템 테스트-통합 테스트-인수 테스트\n④ 통합 테스트-시스템 테스트-인수 테스트-단위 테스트', 'MCQ', 1, '정답: 1. V-모델의 테스트 수행 절차는 단위 테스트 → 통합 테스트 → 시스템 테스트 → 인수 테스트이다.\n\n**오답 풀이**\n- 1번: 올바른 테스트 수행 순서이다.\n- 2번: 인수 테스트가 너무 앞에 배치되어 있다.\n- 3번: 시스템 테스트와 통합 테스트의 순서가 바뀌었다.\n- 4번: 단위 테스트가 마지막에 배치되어 부적절하다.\n\n**보충 개념**\n작은 단위의 모듈 검증부터 전체 시스템과 사용자 요구사항 검증으로 확장된다.',
   'V-모델', 1, @mock_exam_id, 32, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '빅 오(O) 표기법 중, O(1)에 대한 설명으로 옳은 것은?\n\n① 항상 일정한 수행 횟수를 가지는 시간 복잡도이다.\n② 항상 한 번의 수행 횟수를 가지는 시간 복잡도이다.\n③ 연산 횟수가 일정하게 증가하는 시간 복잡도이다.\n④ 연산 횟수가 늘어나는 폭이 점점 커지는 시간 복잡도이다.', 'MCQ', 1, '정답: 1. O(1)은 입력 크기와 관계없이 일정한 수행 횟수를 가지는 시간 복잡도이다.\n\n**오답 풀이**\n- 1번: 입력 크기와 무관하게 일정한 시간이 걸리는 경우이다.\n- 2번: 반드시 한 번만 수행된다는 의미는 아니다.\n- 3번: 연산 횟수가 입력에 비례해 증가하면 O(n)에 가깝다.\n- 4번: 증가 폭이 커지는 경우는 O(n²), O(2^n) 등에 가깝다.\n\n**보충 개념**\nO(1)은 상수 시간 복잡도이며 배열 인덱스 접근 등이 대표적이다.',
   '시간 복잡도', 1, @mock_exam_id, 33, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '다음 중, 소스 코드 정적 분석 도구가 아닌 것은 무엇인가?\n\n① cppcheck\n② checkstyle\n③ Valgrind\n④ SonarQube', 'MCQ', 3, '정답: 3. Valgrind는 실행 중 메모리 오류 등을 분석하는 동적 분석 도구이다.\n\n**오답 풀이**\n- 1번: cppcheck는 C/C++ 정적 분석 도구이다.\n- 2번: checkstyle은 Java 코드 스타일과 규칙 검사를 수행한다.\n- 3번: Valgrind는 동적 분석 도구이다.\n- 4번: SonarQube는 코드 품질과 정적 분석을 지원한다.\n\n**보충 개념**\n정적 분석은 프로그램을 실행하지 않고 소스 코드의 결함과 품질 문제를 검사한다.',
   '정적 분석 도구', 2, @mock_exam_id, 34, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '아래 트리에서 트리의 높이와 노드 9의 깊이를 더한 값은?\n\n**<트리 구조>**\n- 루트 노드는 1이다.\n- 1의 자식은 2, 3이다.\n- 2의 자식은 4, 5이다.\n- 3의 자식은 6, 7이다.\n- 6의 자식은 9이다.\n\n**<조건>**\n- 트리의 높이는 루트에서 가장 깊은 단말 노드까지의 간선 수로 계산한다.\n- 노드의 깊이는 루트에서 해당 노드까지의 간선 수로 계산한다.\n\n① 6\n② 7\n③ 8\n④ 9', 'MCQ', 1, '정답: 1. 루트 1에서 가장 깊은 단말 노드 9까지의 경로는 1→3→6→9이므로 트리의 높이는 3이다. 노드 9의 깊이도 루트에서 9까지의 간선 수인 3이다. 따라서 합은 3+3=6이다.\n\n**오답 풀이**\n- 1번: 높이 3과 깊이 3을 더한 값이다.\n- 2번: 높이나 깊이 중 하나를 노드 수 기준으로 계산한 값에 가깝다.\n- 3번: 간선 수 대신 노드 수를 과도하게 반영한 값이다.\n- 4번: 높이와 깊이를 모두 크게 계산한 값이다.\n\n**보충 개념**\n트리 문제에서는 높이와 깊이를 간선 수 기준으로 세는지, 노드 수 기준으로 세는지 조건을 반드시 확인해야 한다.',
   '트리 높이와 깊이', 3, @mock_exam_id, 35, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '프로그램의 개발 단계별 산출물의 변경 사항 등을 관리하는 기능 및 활동을 뜻하는 용어는 무엇인가?\n\n① 생산 관리\n② 형상 관리\n③ 절차 관리\n④ 유지 보수', 'MCQ', 2, '정답: 2. 개발 산출물의 변경 사항을 식별·통제·관리하는 활동은 형상 관리이다.\n\n**오답 풀이**\n- 1번: 생산 관리는 소프트웨어 산출물 변경 관리와 직접적인 용어가 아니다.\n- 2번: 형상 관리는 변경 사항과 버전을 관리한다.\n- 3번: 절차 관리는 일반적인 절차 관리 의미에 가깝다.\n- 4번: 유지 보수는 운영 중 수정과 개선 활동을 포함하지만 변경 관리 전체를 뜻하지는 않는다.\n\n**보충 개념**\n형상 관리는 변경 원인 파악, 변경 통제, 버전 관리, 상태 보고 등을 포함한다.',
   '형상 관리', 1, @mock_exam_id, 36, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '테스트 원칙 중, 동일한 테스트 케이스로 테스트를 반복 수행하면 새로운 결함 발견이 불가능하다는 것은 무엇인가?\n\n① Defect Clustering\n② Absence of Errors Fallacy\n③ Pesticide Paradox\n④ Pareto’s principle', 'MCQ', 3, '정답: 3. 같은 테스트를 반복하면 새로운 결함을 찾기 어려워지는 원칙은 살충제 패러독스이다.\n\n**오답 풀이**\n- 1번: 결함 집중은 결함이 특정 모듈에 집중되는 현상이다.\n- 2번: 오류 부재의 궤변은 오류가 없어도 요구사항을 만족하지 못하면 품질이 낮다는 원칙이다.\n- 3번: 살충제 패러독스는 같은 테스트 반복의 한계를 뜻한다.\n- 4번: 파레토 원칙은 결함의 대부분이 소수 모듈에 집중된다는 설명과 관련된다.\n\n**보충 개념**\n테스트 케이스는 주기적으로 개선하고 보완해야 새로운 결함을 발견할 수 있다.',
   '테스트 원칙', 1, @mock_exam_id, 37, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '소프트웨어 제품의 개발 과정에 대한 테스트를 의미하는 것은?\n\n① Refactoring\n② Debugging\n③ Validation\n④ Verification', 'MCQ', 4, '정답: 4. 개발 과정에서 명세대로 만들고 있는지 점검하는 것은 검증(Verification)이다.\n\n**오답 풀이**\n- 1번: 리팩토링은 기능을 유지하며 내부 구조를 개선하는 작업이다.\n- 2번: 디버깅은 발견된 결함을 찾아 수정하는 작업이다.\n- 3번: 확인(Validation)은 사용자의 요구사항을 만족하는지 확인한다.\n- 4번: 검증(Verification)은 개발 과정과 산출물이 명세에 맞는지 점검한다.\n\n**보충 개념**\nVerification은 “제품을 올바르게 만들고 있는가”, Validation은 “올바른 제품을 만들었는가”로 구분할 수 있다.',
   '검증과 확인', 2, @mock_exam_id, 38, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '아래와 같은 프로그램 구조에서, 이미지에 적힌 숫자 순으로 테스트를 진행하는 하향식 통합 테스트 방식은 무엇인가?\n\n[그림: 프로그램 구조에서 1번 루트 모듈부터 한쪽 하위 모듈을 깊게 내려가며 1→2→3→4→5→6→7 순서로 테스트하는 구조]\n\n① 중위 우선 방식\n② 깊이 우선 방식\n③ 전위 우선 방식\n④ 너비 우선 방식', 'MCQ', 2, '정답: 2. 하향식 통합 테스트에서 한 경로를 따라 깊게 내려가며 테스트하는 방식은 깊이 우선 방식이다.\n\n**오답 풀이**\n- 1번: 중위 우선은 트리 순회 용어이며 통합 테스트 방식으로 보기 어렵다.\n- 2번: 깊이 우선 방식은 한쪽 하위 모듈을 먼저 깊게 테스트한다.\n- 3번: 전위 우선은 트리 탐색 용어이다.\n- 4번: 너비 우선 방식은 같은 레벨의 모듈을 먼저 테스트한다.\n\n**보충 개념**\n하향식 통합 테스트는 상위 모듈부터 통합하며, 스텁을 사용해 하위 모듈을 대체할 수 있다.',
   '통합 테스트', 2, @mock_exam_id, 39, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '소프트웨어 개발' ORDER BY id LIMIT 1), '아래 트리를 전위 순회 방식으로 탐색할 경우, 4번째로 방문하게 되는 노드는 무엇인가?\n\n**<트리 구조>**\n- 루트 노드는 C이다.\n- C의 왼쪽 자식은 B, 오른쪽 자식은 F이다.\n- B의 왼쪽 자식은 A, 오른쪽 자식은 E이다.\n- E의 왼쪽 자식은 D이다.\n- F의 오른쪽 자식은 G이다.\n\n**<조건>**\n전위 순회는 루트 → 왼쪽 서브트리 → 오른쪽 서브트리 순서로 방문한다.\n\n① A\n② D\n③ E\n④ F', 'MCQ', 3, '정답: 3. 전위 순회는 루트 → 왼쪽 → 오른쪽 순서로 방문한다. 제시된 트리의 전위 순회 결과는 C → B → A → E → D → F → G이므로 4번째 방문 노드는 E이다.\n\n**오답 풀이**\n- 1번: A는 3번째 방문 노드이다.\n- 2번: D는 5번째 방문 노드이다.\n- 3번: E는 4번째 방문 노드이다.\n- 4번: F는 6번째 방문 노드이다.\n\n**보충 개념**\n전위 순회는 Root → Left → Right 순서이다. 각 서브트리에서도 같은 규칙을 반복 적용한다.',
   '전위 순회', 2, @mock_exam_id, 40, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중, 아래에서 설명하는 스키마는 무엇인가?\n\n**<보기>**\n- 물리적인 저장장치 입장에서 데이터베이스가 저장되는 방법이나 구조를 정의한다.\n- 레코드의 저장 형식, 인덱스, 접근 경로, 물리적 배치 등 실제 저장 구조와 관련된다.\n- 데이터가 내부적으로 어떻게 저장되는지를 표현한다.\n\n① 외부 스키마\n② 논리 스키마\n③ 개념 스키마\n④ 내부 스키마', 'MCQ', 4, '정답: 4. 물리적 저장장치 관점에서 데이터베이스의 저장 구조와 접근 방법을 정의하는 것은 내부 스키마이다.\n\n**오답 풀이**\n- 1번: 외부 스키마는 사용자나 응용 프로그램 관점의 부분 논리 구조이다.\n- 2번: 논리 스키마는 일반적으로 데이터의 논리적 구조를 의미하는 표현이다.\n- 3번: 개념 스키마는 조직 전체 관점의 데이터베이스 논리 구조이다.\n- 4번: 내부 스키마는 물리적 저장 구조를 정의한다.\n\n**보충 개념**\n3단계 스키마는 외부 스키마, 개념 스키마, 내부 스키마로 구분된다. 내부 스키마는 저장장치와 접근 경로 등 물리적 구현 관점에 가깝다.',
   '스키마', 2, @mock_exam_id, 41, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '아래의 표를 참고하여 정확한 보기를 고르시오.\n\n| 번호 | 지역 | 업종 | 매출 | 직원수 |\n|---|---|---|---|---|\n| 1 | 서울 | 컨설팅 | 100억 | 100명 |\n| 2 | 부산 | 제조 | 50억 | 50명 |\n| 3 | 대구 | IT | 30억 | 30명 |\n| 4 | 인천 | 금융 | 20억 | 20명 |\n| 5 | 광주 | 서비스 | 10억 | 10명 |\n\n① Relation 5개, Cardinality 1개, Degree 4개\n② Relation 4개, Cardinality 5개, Degree 1개\n③ Relation 1개, Cardinality 5개, Degree 5개\n④ Relation 1개, Cardinality 6개, Degree 5개', 'MCQ', 3, '정답: 3. 표 전체가 하나의 릴레이션이고, 행은 5개, 속성은 번호·지역·업종·매출·직원수 5개이다.\n\n**오답 풀이**\n- 1번: 릴레이션 수와 카디널리티, 차수가 모두 부적절하다.\n- 2번: 릴레이션은 1개이며 차수도 1개가 아니다.\n- 3번: 릴레이션 1개, 카디널리티 5개, 차수 5개가 맞다.\n- 4번: 카디널리티는 제목 행을 제외한 튜플 수이므로 5개이다.\n\n**보충 개념**\nCardinality는 튜플 수, Degree는 속성 수를 의미한다.',
   '릴레이션 구조', 2, @mock_exam_id, 42, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중, 키(key)에 대한 설명과 가장 거리가 먼 것은 무엇인가?\n\n① 데이터를 분류, 정렬하거나 검색할 때의 기준이 되는 속성을 의미한다.\n② 키의 종류에는 후보키, 기본키, 대체키, 슈퍼키, 외래키 등이 있다.\n③ 튜플들에 대해 유일성과 최소성을 모두 만족시키는 속성이다.\n④ 기본키로 지정된 속성을 제외한 후보키를 슈퍼키라고 한다.', 'MCQ', 4, '정답: 4. 기본키로 지정되지 않은 후보키는 대체키이며, 슈퍼키가 아니다.\n\n**오답 풀이**\n- 1번: 키는 검색, 정렬, 식별 기준이 되는 속성이다.\n- 2번: 후보키, 기본키, 대체키, 슈퍼키, 외래키는 키의 종류이다.\n- 3번: 후보키는 유일성과 최소성을 만족한다.\n- 4번: 기본키가 아닌 후보키는 대체키라고 한다.\n\n**보충 개념**\n슈퍼키는 유일성을 만족하는 속성 집합이며 최소성은 요구하지 않는다.',
   '키', 2, @mock_exam_id, 43, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중, 데이터 모델링 단계에 해당하지 않는 것은?\n\n① 개념 모델링\n② 논리 모델링\n③ 추상 모델링\n④ 물리 모델링', 'MCQ', 3, '정답: 3. 데이터 모델링 단계는 일반적으로 개념 모델링, 논리 모델링, 물리 모델링으로 구분된다.\n\n**오답 풀이**\n- 1번: 개념 모델링은 업무 개념과 주요 개체를 도출하는 단계이다.\n- 2번: 논리 모델링은 논리적 데이터 구조를 설계하는 단계이다.\n- 3번: 추상 모델링은 표준 데이터 모델링 단계 명칭이 아니다.\n- 4번: 물리 모델링은 실제 DBMS 구현 구조를 설계하는 단계이다.\n\n**보충 개념**\n개념 → 논리 → 물리 순서로 점점 구현에 가까운 모델을 만든다.',
   '데이터 모델링 단계', 1, @mock_exam_id, 44, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '아래가 설명하는 논리 개체 관계로 올바른 것은 무엇인가?\n\n**<보기>**\n- 개체와 개체 사이의 주종 관계를 나타낸 것으로 식별 관계와 비식별 관계가 있다.\n- 식별 관계: 개체의 외래키가 기본키에 포함되는 관계\n- 비식별 관계: 개체의 외래키가 기본키에 포함되지 않는 관계\n\n① Dependent\n② Redundant\n③ Recursive\n④ Mutually Exclusive', 'MCQ', 1, '정답: 1. 개체 사이의 주종 관계를 나타내는 것은 종속 관계(Dependent Relationship)이다.\n\n**오답 풀이**\n- 1번: Dependent는 식별·비식별 관계를 포함하는 종속 관계이다.\n- 2번: Redundant는 두 개체 사이에 중복 관계가 발생하는 경우이다.\n- 3번: Recursive는 개체가 자기 자신과 관계를 맺는 경우이다.\n- 4번: Mutually Exclusive는 배타 관계이다.\n\n**보충 개념**\n식별 관계에서는 자식 엔터티의 외래키가 기본키의 일부가 된다.',
   '식별 관계', 2, @mock_exam_id, 45, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중, 시스템 카탈로그에 대한 설명으로 가장 거리가 먼 것은?\n\n① DBMS가 스스로 생성하고 유지한다.\n② DB 객체가 변경되면 자동으로 반영된다.\n③ DML을 통해 조회 및 변경이 가능하다.\n④ 데이터 사전으로도 불리며 메타 데이터가 포함된다.', 'MCQ', 3, '정답: 3. 시스템 카탈로그는 사용자가 직접 변경할 수 없으며 DBMS가 자동으로 갱신한다.\n\n**오답 풀이**\n- 1번: 시스템 카탈로그는 DBMS가 생성하고 유지한다.\n- 2번: 기본 테이블, 뷰, 인덱스 등이 변경되면 자동 반영된다.\n- 3번: 조회는 가능하지만 직접적인 변경은 불가능하다.\n- 4번: 시스템 카탈로그는 데이터 사전이라고도 하며 메타데이터를 포함한다.\n\n**보충 개념**\n시스템 카탈로그는 데이터베이스 객체에 대한 정보를 저장하는 메타데이터 저장소이다.',
   '시스템 카탈로그', 2, @mock_exam_id, 46, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 트랜잭션의 특징 중, 모든 연산이 수행되거나 하나도 수행되지 말아야 한다는 것은 무엇인가?\n\n① Atomicity\n② Isolation\n③ Consistency\n④ Durability', 'MCQ', 1, '정답: 1. 모든 연산이 전부 수행되거나 전혀 수행되지 않아야 하는 특성은 원자성이다.\n\n**오답 풀이**\n- 1번: 원자성은 All or Nothing 특성이다.\n- 2번: 격리성은 트랜잭션 중간 결과가 다른 트랜잭션에 간섭되지 않는 성질이다.\n- 3번: 일관성은 트랜잭션 후 데이터베이스가 일관된 상태를 유지하는 성질이다.\n- 4번: 지속성은 완료된 트랜잭션 결과가 영구 반영되는 성질이다.\n\n**보충 개념**\n트랜잭션의 ACID는 Atomicity, Consistency, Isolation, Durability이다.',
   '트랜잭션 ACID', 1, @mock_exam_id, 47, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '국어, 영어, 수학 점수가 기록되어 있는 릴레이션에 과학 속성을 추가하기 위해 필요한 데이터베이스 명령어는 무엇인가?\n\n① INSERT\n② UPDATE\n③ ALTER\n④ SHIFT', 'MCQ', 3, '정답: 3. 기존 테이블에 속성을 추가하려면 ALTER 명령어를 사용한다.\n\n**오답 풀이**\n- 1번: INSERT는 새로운 튜플을 삽입하는 DML이다.\n- 2번: UPDATE는 기존 튜플의 값을 변경하는 DML이다.\n- 3번: ALTER는 테이블 구조를 변경하는 DDL이다.\n- 4번: SHIFT는 SQL의 표준 데이터 정의 명령이 아니다.\n\n**보충 개념**\n테이블 구조 변경에는 ALTER TABLE을 사용한다.',
   'DDL', 1, @mock_exam_id, 48, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), 'VIEW에 대한 설명으로 옳지 않은 것은?\n\n① 물리적으로 실존하는 객체이다.\n② 시스템 카탈로그에 저장된다.\n③ 뷰를 통해 또 다른 뷰를 정의할 수 있다.\n④ 종속된 테이블이 제거되면 함께 제거된다.', 'MCQ', 1, '정답: 1. 뷰는 실제 데이터를 물리적으로 저장하는 테이블이 아니라 논리적으로 유도된 가상의 테이블이다.\n\n**오답 풀이**\n- 1번: 뷰는 물리적으로 실존하는 테이블이 아니다.\n- 2번: 뷰의 정의는 시스템 카탈로그에 저장된다.\n- 3번: 뷰를 기반으로 다른 뷰를 정의할 수 있다.\n- 4번: 기반 테이블이 제거되면 해당 뷰도 영향을 받는다.\n\n**보충 개념**\n뷰는 보안, 논리적 독립성, 사용자 편의성을 높이기 위해 사용된다.',
   '뷰', 2, @mock_exam_id, 49, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '논리 데이터 모델을 시스템 운영의 단순화를 위해서 중복, 통합, 분할 등을 수행하는 데이터 모델링 기법은 무엇인가?\n\n① Clustering\n② Partitioning\n③ De-Normalization\n④ Sharding', 'MCQ', 3, '정답: 3. 성능 향상과 운영 편의성을 위해 의도적으로 중복, 통합, 분할을 수행하는 것은 반정규화이다.\n\n**오답 풀이**\n- 1번: 클러스터링은 여러 서버를 하나처럼 운영하는 기술이다.\n- 2번: 파티셔닝은 대용량 테이블을 논리 단위로 나누는 기술이다.\n- 3번: 반정규화는 정규화된 모델을 성능과 운영 편의상 중복·통합·분할한다.\n- 4번: 샤딩은 데이터를 여러 저장소에 분산 저장하는 방식이다.\n\n**보충 개념**\n반정규화는 조회 성능 향상에는 유리하지만 데이터 중복과 정합성 관리 부담을 증가시킬 수 있다.',
   '반정규화', 2, @mock_exam_id, 50, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '서버와 저장장치를 직접 연결하는 스토리지 유형은 무엇인가?\n\n① NAS\n② SAN\n③ SAD\n④ DAS', 'MCQ', 4, '정답: 4. 서버와 저장장치를 전용 케이블로 직접 연결하는 방식은 DAS이다.\n\n**오답 풀이**\n- 1번: NAS는 네트워크를 통해 파일 단위 저장소를 제공한다.\n- 2번: SAN은 전용 스토리지 네트워크를 구성한다.\n- 3번: SAD는 대표적인 스토리지 유형 명칭이 아니다.\n- 4번: DAS는 서버에 저장장치를 직접 연결하는 방식이다.\n\n**보충 개념**\nDAS는 구성이 단순하고 빠르지만 공유성과 확장성은 NAS나 SAN보다 제한적일 수 있다.',
   '스토리지', 1, @mock_exam_id, 51, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '특정 열에 중복값 또는 Null에 대한 제한을 두어 개체 식별자의 역할을 할 수 있게 하는 데이터베이스 무결성은 무엇인가?\n\n① 개체 무결성\n② 도메인 무결성\n③ 참조 무결성\n④ 사용자 무결성', 'MCQ', 1, '정답: 1. 기본키가 Null이나 중복값을 가질 수 없도록 하는 제약은 개체 무결성이다.\n\n**오답 풀이**\n- 1번: 개체 무결성은 기본키의 Null과 중복을 허용하지 않는다.\n- 2번: 도메인 무결성은 속성값이 정의된 도메인에 속해야 한다는 제약이다.\n- 3번: 참조 무결성은 외래키가 참조 대상 기본키와 일치하거나 Null이어야 한다는 제약이다.\n- 4번: 사용자 무결성은 사용자가 정의한 제약 조건이다.\n\n**보충 개념**\n개체 무결성은 릴레이션의 각 튜플을 유일하게 식별하기 위한 기본 제약이다.',
   '개체 무결성', 1, @mock_exam_id, 52, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '속성 A, B, C에 대한 관계식이 아래와 같을 때, 해당되는 종속성은 무엇인가?\n\n**<보기>**\nA → B, B → C, A → C\n\n① 이행적 종속\n② 완전 함수 종속\n③ 부분 함수 종속\n④ 배타적 종속', 'MCQ', 1, '정답: 1. A가 B를 결정하고 B가 C를 결정하여 A가 C를 간접적으로 결정하므로 이행적 종속이다.\n\n**오답 풀이**\n- 1번: A → B, B → C이면 A → C가 성립하는 이행적 종속이다.\n- 2번: 완전 함수 종속은 복합키 전체에 종속되는 경우이다.\n- 3번: 부분 함수 종속은 복합키의 일부에만 종속되는 경우이다.\n- 4번: 배타적 종속은 해당 함수 종속 개념과 거리가 있다.\n\n**보충 개념**\n제3정규형은 이행적 종속을 제거하는 정규형이다.',
   '함수 종속', 2, @mock_exam_id, 53, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중, 로크의 단위가 큰 경우에 해당하지 않는 것은?\n\n① 병행성 수준이 낮아진다.\n② 오버헤드가 증가한다.\n③ 로크의 개수가 적어진다.\n④ 병행 제어 기법이 단순해진다.', 'MCQ', 2, '정답: 2. 로크 단위가 클수록 로크 개수는 줄어들어 오버헤드는 감소한다.\n\n**오답 풀이**\n- 1번: 큰 단위로 잠그면 동시에 접근 가능한 범위가 줄어 병행성이 낮아진다.\n- 2번: 로크 수가 적어지므로 오버헤드는 증가가 아니라 감소한다.\n- 3번: 로크 단위가 크면 관리해야 할 로크 개수가 적어진다.\n- 4번: 로크 수가 적으므로 병행 제어가 단순해진다.\n\n**보충 개념**\n로크 단위가 작으면 병행성은 높아지지만 관리 오버헤드는 증가한다.',
   '로킹 단위', 2, @mock_exam_id, 54, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중, 결정자가 후보키가 아닌 함수 종속을 제거하여 모든 결정자가 후보키인 정규형은 무엇인가?\n\n① 1NF\n② BCNF\n③ 2NF\n④ 3NF', 'MCQ', 2, '정답: 2. 모든 결정자가 후보키가 되도록 하는 정규형은 BCNF이다.\n\n**오답 풀이**\n- 1번: 1NF는 속성값의 원자성을 만족하는 정규형이다.\n- 2번: BCNF는 모든 결정자가 후보키여야 한다.\n- 3번: 2NF는 부분 함수 종속을 제거한다.\n- 4번: 3NF는 이행적 함수 종속을 제거한다.\n\n**보충 개념**\nBCNF는 3NF보다 강한 정규형으로, 결정자 제약을 더 엄격하게 적용한다.',
   'BCNF', 2, @mock_exam_id, 55, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중, DDL 명령어에 해당하지 않는 것은?\n\n① CREATE\n② ALTER\n③ TRUNCATE\n④ REVOKE', 'MCQ', 4, '정답: 4. REVOKE는 권한을 회수하는 DCL 명령어이다.\n\n**오답 풀이**\n- 1번: CREATE는 객체를 생성하는 DDL이다.\n- 2번: ALTER는 객체 구조를 변경하는 DDL이다.\n- 3번: TRUNCATE는 테이블 데이터를 초기화하는 DDL로 분류된다.\n- 4번: REVOKE는 권한 회수 명령으로 DCL이다.\n\n**보충 개념**\nDDL은 CREATE, ALTER, DROP, TRUNCATE 등이 대표적이다.',
   'DDL', 1, @mock_exam_id, 56, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중, 이상 현상이 아닌 것은 무엇인가?\n\n① 삭제 이상\n② 삽입 이상\n③ 갱신 이상\n④ 권한 이상', 'MCQ', 4, '정답: 4. 데이터베이스 이상 현상에는 삽입 이상, 삭제 이상, 갱신 이상이 있으며 권한 이상은 해당하지 않는다.\n\n**오답 풀이**\n- 1번: 삭제 이상은 의도하지 않은 정보까지 삭제되는 현상이다.\n- 2번: 삽입 이상은 불필요한 정보 없이는 데이터를 삽입하기 어려운 현상이다.\n- 3번: 갱신 이상은 일부 데이터만 변경되어 불일치가 생기는 현상이다.\n- 4번: 권한 이상은 정규화에서 말하는 이상 현상이 아니다.\n\n**보충 개념**\n이상 현상은 정규화를 통해 줄일 수 있다.',
   '이상 현상', 1, @mock_exam_id, 57, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '다음 중, 함수 종속에 대해 A→B를 올바르게 해석한 것은?\n\n① A 속성은 B 속성에 함수적으로 종속된다.\n② B 속성은 A 속성에 함수적으로 종속된다.\n③ A 속성은 종속자, B 속성은 결정자이다.\n④ B 속성은 A 속성에 대해 부분집합이다.', 'MCQ', 2, '정답: 2. A→B는 A가 B를 결정하며, B가 A에 함수적으로 종속된다는 의미이다.\n\n**오답 풀이**\n- 1번: 종속 방향을 반대로 해석했다.\n- 2번: B는 A에 함수적으로 종속된다.\n- 3번: A는 결정자, B는 종속자이다.\n- 4번: 함수 종속은 부분집합 관계를 뜻하지 않는다.\n\n**보충 개념**\nA→B에서 왼쪽 A는 결정자, 오른쪽 B는 종속자이다.',
   '함수 종속', 1, @mock_exam_id, 58, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '아래 ‘학과정보’ 테이블에 대한 SQL문의 실행 결과로 옳은 것은?\n\n| 학과 | 인원 | 평균학점 | 담당교수 | 강의실 |\n|---|---:|---:|---|---|\n| 건축 | 40 | 3.5 | A | 201 |\n| 교육 | 50 | 2.7 | B | 304 |\n| 복지 | 30 | 4.1 | C | 107 |\n| 경영 | 30 | 4.3 | D | 303 |\n| 관광 | 40 | 3.3 | E | 402 |\n\n```sql\nselect COUNT(*) from 학과정보 where 평균학점 > 3.5;\nselect AVG(인원) from 학과정보 where 담당교수 NOT IN(''A'', ''D'');\n```\n\n① 3, 40\n② 2, 40\n③ 3, 38\n④ 2, 38', 'MCQ', 2, '정답: 2. 평균학점이 3.5 초과인 행은 복지, 경영 2개이고, 담당교수가 A와 D가 아닌 행의 인원 평균은 (50+30+40)/3 = 40이다.\n\n**오답 풀이**\n- 1번: 평균학점 3.5는 초과 조건에 포함되지 않으므로 COUNT는 3이 아니다.\n- 2번: COUNT는 2, AVG는 40으로 맞다.\n- 3번: COUNT와 AVG가 모두 맞지 않는다.\n- 4번: COUNT는 맞지만 AVG 계산이 틀렸다.\n\n**보충 개념**\nSQL에서 `>`는 초과 조건이므로 3.5와 같은 값은 제외된다.',
   'SQL 집계 함수', 2, @mock_exam_id, 59, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '데이터베이스 구축' ORDER BY id LIMIT 1), '송도지점의 날짜별 매출기록을 내림차순으로 조회할 때 필요한 명령어가 올바르게 나열된 것은?\n\n① select 날짜, 매출 from 매출현황 where 지점=''송도'' order by 날짜 DESC\n② select 날짜, 매출 from 매출현황 where 지점=''송도'' order by 날짜 ASC\n③ select 날짜, 매출 from 매출현황 where 지점=''송도'' sort by 날짜 DESC\n④ select 날짜, 매출 from 매출현황 where 지점=''송도'' sort by 날짜 ASC', 'MCQ', 1, '정답: 1. 조건 검색은 WHERE, 정렬은 ORDER BY, 내림차순은 DESC를 사용한다.\n\n**오답 풀이**\n- 1번: 송도 지점을 조건으로 필터링하고 날짜 기준 내림차순 정렬하므로 맞다.\n- 2번: ASC는 오름차순이다.\n- 3번: 표준 SQL 정렬 구문은 SORT BY가 아니라 ORDER BY이다.\n- 4번: SORT BY도 부적절하고 ASC는 오름차순이다.\n\n**보충 개념**\nORDER BY의 기본 정렬은 ASC이며, 내림차순은 DESC를 명시한다.',
   'ORDER BY', 1, @mock_exam_id, 60, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 Python 코드의 실행결과로 올바른 것은 무엇인가?\n\n```python\na = [[0 for a in range(2)] for b in range(3)]\nprint(a)\n```\n\n① [0, 0, 0, 0, 0, 0]\n② [[0, 0], [0, 0], [0, 0]]\n③ [[0, 0, 0], [0, 0, 0]]\n④ [[0, 0], [0, 0, 0]]', 'MCQ', 2, '정답: 2. 내부 리스트 `[0, 0]`가 바깥 반복문에 의해 3개 생성되므로 `[[0, 0], [0, 0], [0, 0]]`가 출력된다.\n\n**오답 풀이**\n- 1번: 1차원 리스트가 아니라 2차원 리스트가 생성된다.\n- 2번: 길이 2의 리스트가 3개 생성되어 맞다.\n- 3번: 길이 3의 리스트가 2개 생성되는 구조가 아니다.\n- 4번: 각 내부 리스트의 길이는 동일하게 2이다.\n\n**보충 개념**\n리스트 컴프리헨션에서 안쪽 표현식이 먼저 생성되고 바깥 반복에 따라 반복된다.',
   'Python 리스트 컴프리헨션', 2, @mock_exam_id, 61, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 C 코드의 for문을 while문으로 올바르게 변환한 것은 무엇인가?\n\n```c\nfor(i=0; i<10; i++){\n    sum += i;\n}\n```\n\n① while(i<10){\n    i=0;\n    i++;\n    sum+=i;\n}\n② i=0;\nwhile(i<10){\n    i++;\n    sum+=i;\n}\n③ i=0;\nwhile(i<10){\n    sum+=i;\n    i++;\n}\n④ while(i<10){\n    i=0;\n    sum+=i;\n    i++;\n}', 'MCQ', 3, '정답: 3. for문의 초기식은 반복문 전에, 증감식은 반복문 본문 실행 후에 수행되어야 한다.\n\n**오답 풀이**\n- 1번: 반복문 내부에서 매번 i를 0으로 초기화해 무한 반복 위험이 있다.\n- 2번: i를 더하기 전에 증가시키므로 더하는 값의 순서가 달라진다.\n- 3번: i=0으로 초기화 후 sum에 더하고 마지막에 i++를 수행하므로 원래 for문과 같다.\n- 4번: 반복문 내부에서 i를 계속 0으로 초기화해 부적절하다.\n\n**보충 개념**\n`for(초기식; 조건식; 증감식){본문}`은 `초기식; while(조건식){본문; 증감식;}`으로 변환할 수 있다.',
   'C 반복문', 2, @mock_exam_id, 62, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 C 코드에 선언된 변수 c의 값을 출력하기 위한 서식문자로 가장 부적절한 것은?\n\n```c\nchar c = 70;\n```\n\n① %d\n② %c\n③ %f\n④ %x', 'MCQ', 3, '정답: 3. `char` 값은 정수 계열로 취급할 수 있지만 `%f`는 실수 출력 서식이므로 부적절하다.\n\n**오답 풀이**\n- 1번: `%d`는 정수값으로 출력할 수 있다.\n- 2번: `%c`는 문자로 출력할 수 있다.\n- 3번: `%f`는 부동소수점 실수 출력에 사용되므로 부적절하다.\n- 4번: `%x`는 정수값을 16진수로 출력할 수 있다.\n\n**보충 개념**\nC에서 `char`는 문자형이지만 내부적으로 정수 코드값을 저장한다.',
   'C 서식 지정자', 2, @mock_exam_id, 63, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 C 코드를 참고하여 값이 나머지 셋과 다른 것을 고르시오.\n\n```c\nint ar[2][2] = {{11, 22}, {33, 44}};\nint *p = &ar[0][0];\n```\n\n**<보기 표현식>**\n1. `ar[0][1]`\n2. `p[1]`\n3. `*(p + 1)`\n4. `**(ar + 1)`\n\n① ar[0][1]\n② p[1]\n③ *(p + 1)\n④ **(ar + 1)', 'MCQ', 4, '정답: 4. `ar[0][1]`, `p[1]`, `*(p+1)`은 모두 배열의 두 번째 원소인 22를 의미한다. 반면 `**(ar+1)`은 두 번째 행의 첫 번째 원소인 `ar[1][0]`, 즉 33을 의미한다.\n\n**오답 풀이**\n- 1번: `ar[0][1]`은 22이다.\n- 2번: `p`가 `&ar[0][0]`을 가리키므로 `p[1]`은 22이다.\n- 3번: `*(p+1)`도 `p[1]`과 같으므로 22이다.\n- 4번: `ar+1`은 두 번째 행을 가리키고, 이를 역참조하면 두 번째 행의 시작 원소 33을 얻는다.\n\n**보충 개념**\n2차원 배열에서 `ar`은 행 단위 포인터처럼 동작한다. `ar+1`은 다음 행을 가리키며, `**(ar+1)`은 두 번째 행의 첫 번째 값을 의미한다.',
   'C 포인터와 배열', 4, @mock_exam_id, 64, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 C 코드의 실행결과로 올바른 것은 무엇인가?\n\n```c\nint fn(int* x, int n){\n    if(n==1) return 1;\n    return *x + fn(x, n-1);\n}\nint main(){\n    int x=5;\n    printf("%d", fn(&x, x));\n    return 0;\n}\n```\n\n① 21\n② 25\n③ 15\n④ 5', 'MCQ', 1, '정답: 1. `fn(&x,5)`는 `5+5+5+5+1`을 계산하므로 21이 출력된다.\n\n**오답 풀이**\n- 1번: 재귀 호출이 n=1에서 1을 반환하므로 총합은 21이다.\n- 2번: n=1에서도 5를 더한다고 착각한 값이다.\n- 3번: 재귀 횟수를 부족하게 계산한 값이다.\n- 4번: 첫 번째 포인터 값만 출력하는 코드가 아니다.\n\n**보충 개념**\n재귀 함수는 종료 조건과 각 호출에서 누적되는 값을 정확히 추적해야 한다.',
   'C 재귀', 3, @mock_exam_id, 65, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 Python 코드의 실행결과로 올바른 것은 무엇인가?\n\n```python\na = [1, 2, 3, 4, 5, 6, 7, 8]\na[:5:2] = (10, 20, 30)\nprint(a)\n```\n\n① 오류\n② [11, 22, 33, 14, 25, 36, 17, 28]\n③ [10, 20, 30, 4, 5, 6, 7, 8]\n④ [10, 2, 20, 4, 30, 6, 7, 8]', 'MCQ', 4, '정답: 4. `a[:5:2]`는 인덱스 0, 2, 4를 선택하므로 해당 위치에 10, 20, 30이 대입된다.\n\n**오답 풀이**\n- 1번: 선택된 원소 수와 대입 원소 수가 같으므로 오류가 발생하지 않는다.\n- 2번: 각 원소를 계산해 바꾸는 코드가 아니다.\n- 3번: 앞의 세 원소를 연속으로 바꾸는 슬라이싱이 아니다.\n- 4번: 인덱스 0, 2, 4만 변경되므로 맞다.\n\n**보충 개념**\n확장 슬라이싱 대입에서는 선택된 위치의 개수와 대입할 값의 개수가 같아야 한다.',
   'Python 슬라이싱', 3, @mock_exam_id, 66, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '아래 Java 코드의 실행결과로 올바른 것은 무엇인가?\n\n```java\nclass A{\n    public int func(int a, int b){\n        return a+b;\n    }\n}\nclass B extends A{\n    public double func(double a, double b){\n        return a-b;\n    }\n}\npublic class Main{\n    public static void main(String[] args) {\n        int a=10, b=5;\n        B x = new B();\n        System.out.println(x.func(a, b));\n    }\n}\n```\n\n① 10\n② 15\n③ 5\n④ 20', 'MCQ', 2, '정답: 2. 인수 `a`, `b`가 int이므로 상속받은 `func(int, int)`가 호출되어 10+5=15가 출력된다.\n\n**오답 풀이**\n- 1번: 10은 계산 결과가 아니다.\n- 2번: `A`의 int 매개변수 메서드가 호출되어 15가 맞다.\n- 3번: `B`의 double 매개변수 메서드가 호출되어 뺄셈한다고 본 값이다.\n- 4번: 코드상 곱셈이나 다른 연산이 없다.\n\n**보충 개념**\n매개변수 타입이 다르면 오버라이딩이 아니라 오버로딩이며, 호출 시 가장 적합한 시그니처가 선택된다.',
   'Java 오버로딩', 3, @mock_exam_id, 67, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), 'Java에서 실행 가능한 기본 출력 메소드가 아닌 것은 무엇인가?\n\n① System.out.print()\n② System.out.printb()\n③ System.out.println()\n④ System.out.printf()', 'MCQ', 2, '정답: 2. Java 표준 출력 메서드에는 `print`, `println`, `printf`가 있으며 `printb`는 없다.\n\n**오답 풀이**\n- 1번: `System.out.print()`는 줄바꿈 없이 출력한다.\n- 2번: `System.out.printb()`는 기본 출력 메서드가 아니다.\n- 3번: `System.out.println()`은 출력 후 줄바꿈한다.\n- 4번: `System.out.printf()`는 형식 문자열에 맞춰 출력한다.\n\n**보충 개념**\nJava의 표준 출력은 `System.out` 객체의 메서드를 통해 수행한다.',
   'Java 출력', 1, @mock_exam_id, 68, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중, 디자인 패턴의 유형이 아닌 것은 무엇인가?\n\n① 상속\n② 생성\n③ 행위\n④ 구조', 'MCQ', 1, '정답: 1. GoF 디자인 패턴의 유형은 생성, 구조, 행위 패턴이며 상속은 유형이 아니다.\n\n**오답 풀이**\n- 1번: 상속은 객체지향 개념이지 디자인 패턴 유형이 아니다.\n- 2번: 생성 패턴은 객체 생성 방식과 관련된다.\n- 3번: 행위 패턴은 객체 간 책임 분배와 상호작용에 관한 패턴이다.\n- 4번: 구조 패턴은 클래스나 객체의 조합 구조와 관련된다.\n\n**보충 개념**\nGoF 디자인 패턴은 생성 5개, 구조 7개, 행위 11개로 분류된다.',
   '디자인 패턴 유형', 1, @mock_exam_id, 69, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중, 디자인 패턴의 유형이 나머지 셋과 다른 하나는?\n\n① Memento\n② State\n③ Decorator\n④ Command', 'MCQ', 3, '정답: 3. Decorator는 구조 패턴이고, Memento, State, Command는 행위 패턴이다.\n\n**오답 풀이**\n- 1번: Memento는 행위 패턴이다.\n- 2번: State는 행위 패턴이다.\n- 3번: Decorator는 객체에 기능을 동적으로 추가하는 구조 패턴이다.\n- 4번: Command는 요청을 객체로 캡슐화하는 행위 패턴이다.\n\n**보충 개념**\n구조 패턴은 객체 조합 구조를, 행위 패턴은 객체 간 상호작용과 책임 분배를 다룬다.',
   '디자인 패턴', 2, @mock_exam_id, 70, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중, 리눅스 버전 등의 시스템 정보를 출력하는 리눅스 명령어는 무엇인가?\n\n① chown\n② fork\n③ chdir\n④ uname', 'MCQ', 4, '정답: 4. `uname`은 리눅스 커널 및 시스템 정보를 출력하는 명령어이다.\n\n**오답 풀이**\n- 1번: `chown`은 파일이나 디렉터리의 소유자와 그룹을 변경한다.\n- 2번: `fork`는 프로세스 생성과 관련된 시스템 호출이다.\n- 3번: `chdir`은 현재 작업 디렉터리를 변경한다.\n- 4번: `uname`은 시스템 정보를 출력한다.\n\n**보충 개념**\n`uname -a`를 사용하면 커널명, 호스트명, 커널 버전 등 전체 정보를 확인할 수 있다.',
   'Linux 명령어', 1, @mock_exam_id, 71, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중, 아래에서 설명하는 객체지향 기술은 무엇인가?\n\n**<보기>**\n- 캡슐화의 가장 큰 목적으로 실제 구현되는 내용의 일부를 외부로부터 감추는 것이다.\n- 클래스 내부 속성과 메소드를 외부의 영향으로부터 보호할 수 있도록 설계하는 방법이다.\n\n① Information Hiding\n② Polymorphism\n③ Abstract\n④ Inheritance', 'MCQ', 1, '정답: 1. 내부 구현 정보를 외부로부터 감추는 객체지향 원리는 정보 은닉이다.\n\n**오답 풀이**\n- 1번: Information Hiding은 내부 구현을 숨기고 공개 인터페이스로만 접근하게 한다.\n- 2번: Polymorphism은 같은 메시지에 객체마다 다르게 응답하는 성질이다.\n- 3번: Abstract는 공통 특징을 추출해 모델화하는 추상화이다.\n- 4번: Inheritance는 상위 클래스의 속성과 메서드를 하위 클래스가 물려받는 것이다.\n\n**보충 개념**\n정보 은닉은 캡슐화를 통해 변경 영향 범위를 줄이고 객체의 자율성을 높인다.',
   '정보 은닉', 1, @mock_exam_id, 72, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중, 정수를 저장할 수 있는 자료형이 아닌 것은?\n\n① int\n② short\n③ double\n④ long', 'MCQ', 3, '정답: 3. `double`은 부동소수점 실수를 저장하는 자료형이다.\n\n**오답 풀이**\n- 1번: `int`는 정수형이다.\n- 2번: `short`는 정수형이다.\n- 3번: `double`은 실수형이다.\n- 4번: `long`은 정수형이다.\n\n**보충 개념**\n정수형에는 일반적으로 char, short, int, long 등이 있고 실수형에는 float, double 등이 있다.',
   '자료형', 1, @mock_exam_id, 73, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중, 은행원 알고리즘은 교착 상태의 해결 방법 중 어떤 기법에 해당하는가?\n\n① Recovery\n② Detection\n③ Avoidance\n④ Prevention', 'MCQ', 3, '정답: 3. 은행원 알고리즘은 교착 상태가 발생하지 않는 안전 상태를 유지하도록 하는 회피 기법이다.\n\n**오답 풀이**\n- 1번: Recovery는 교착 상태 발생 후 회복하는 기법이다.\n- 2번: Detection은 교착 상태 발생 여부를 탐지하는 기법이다.\n- 3번: Avoidance는 발생 가능성을 판단해 안전한 경우에만 자원을 할당한다.\n- 4번: Prevention은 교착 상태 조건 중 하나를 사전에 제거하는 기법이다.\n\n**보충 개념**\n은행원 알고리즘은 자원 할당 요청 시 시스템이 안전 상태를 유지할 수 있는지 검사한다.',
   '교착 상태 회피', 2, @mock_exam_id, 74, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중, 사용자 명령 해석을 통해 시스템의 기능 수행을 돕는 유닉스의 구성요소는 무엇인가?\n\n① Shell\n② Utility\n③ Micro-Kernel\n④ Monolithic-Kernel', 'MCQ', 1, '정답: 1. 사용자의 명령을 해석하고 커널에 전달하는 구성요소는 Shell이다.\n\n**오답 풀이**\n- 1번: Shell은 명령어 해석기 역할을 한다.\n- 2번: Utility는 사용자가 활용하는 응용 프로그램이나 도구이다.\n- 3번: Micro-Kernel은 커널 구조 방식 중 하나이다.\n- 4번: Monolithic-Kernel은 커널 구조 방식 중 하나이다.\n\n**보충 개념**\n유닉스는 커널, 쉘, 유틸리티 프로그램으로 구성된다.',
   'UNIX 구성요소', 1, @mock_exam_id, 75, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중, 자료 흐름도를 활용하여 입출력 데이터, 세부 기능 등을 결정하는 럼바우 분석 절차는 무엇인가?\n\n① 객체 모델링\n② 동적 모델링\n③ 기능 모델링\n④ 개념 모델링', 'MCQ', 3, '정답: 3. 자료 흐름도(DFD)를 활용해 입출력과 처리 기능을 모델링하는 것은 기능 모델링이다.\n\n**오답 풀이**\n- 1번: 객체 모델링은 객체와 객체 간 관계를 정의한다.\n- 2번: 동적 모델링은 시간 흐름에 따른 상태 변화와 동작을 표현한다.\n- 3번: 기능 모델링은 자료 흐름도를 사용한다.\n- 4번: 개념 모델링은 럼바우 분석의 대표 절차 명칭이 아니다.\n\n**보충 개념**\n럼바우 분석 절차는 객체 모델링 → 동적 모델링 → 기능 모델링 순서로 진행된다.',
   '럼바우 분석', 2, @mock_exam_id, 76, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '다음 중, 아래 내용이 설명하는 리눅스 로그 파일은 무엇인가?\n\n**<보기>**\n- 리눅스 시스템에서 사용자의 성공한 로그인/로그아웃 정보 기록\n- 시스템의 종료/시작 시간 기록\n\n① tapping\n② wtmp\n③ xtslog\n④ linuxer', 'MCQ', 2, '정답: 2. `wtmp`는 성공한 로그인/로그아웃 및 시스템 시작·종료 정보를 기록하는 로그 파일이다.\n\n**오답 풀이**\n- 1번: tapping은 대표적인 리눅스 로그인 기록 파일명이 아니다.\n- 2번: wtmp는 로그인/로그아웃과 시스템 on/off 정보를 기록한다.\n- 3번: xtslog는 일반적인 표준 로그 파일명이 아니다.\n- 4번: linuxer는 표준 로그 파일명이 아니다.\n\n**보충 개념**\n리눅스 로그 파일은 `/var/log` 아래에 저장되는 경우가 많다.',
   'Linux 로그', 1, @mock_exam_id, 77, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '10.100.240.0/22 네트워크에서 FLSM 방식으로 10개의 subnet으로 나누었을 때, 2번째 서브넷의 5번째 유효한 IP주소는 무엇인가? (단, ip subnet-zero는 적용하지 않는다.)\n\n① 10.100.240.132\n② 10.100.240.133\n③ 10.100.240.69\n④ 10.100.240.68', 'MCQ', 2, '정답: 2. /22를 10개 이상으로 나누려면 4비트를 빌려 16개 서브넷으로 나누며, 새 prefix는 /26이고 블록 크기는 64이다. subnet-zero를 적용하지 않으므로 0번 서브넷을 제외하고, 2번째 사용 서브넷은 10.100.240.128/26이다. 유효 IP는 129부터 시작하므로 5번째 유효 IP는 10.100.240.133이다.\n\n**오답 풀이**\n- 1번: 10.100.240.132는 4번째 유효 IP이다.\n- 2번: 10.100.240.133은 5번째 유효 IP이다.\n- 3번: 10.100.240.69는 첫 번째 사용 서브넷 범위에 해당한다.\n- 4번: 10.100.240.68은 첫 번째 사용 서브넷 범위에 해당한다.\n\n**보충 개념**\nFLSM에서는 모든 서브넷의 크기가 동일하며, 필요한 서브넷 수를 만족하도록 비트를 빌린다.',
   '서브넷팅', 4, @mock_exam_id, 78, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '작업별 실행 시간과 대기 시간이 아래 표와 같을 때, HRN 방식을 적용할 경우 가장 먼저 수행되는 작업은 무엇인가?\n\n| 작업 | 실행시간 | 대기시간 |\n|---|---:|---:|\n| A | 15 | 18 |\n| B | 12 | 24 |\n| C | 25 | 20 |\n| D | 4 | 10 |\n\n① B\n② D\n③ A\n④ C', 'MCQ', 2, '정답: 2. HRN 우선순위는 (대기시간+실행시간)/실행시간이다. A=2.2, B=3, C=1.8, D=3.5이므로 D가 가장 먼저 수행된다.\n\n**오답 풀이**\n- 1번: B의 우선순위는 3으로 D보다 낮다.\n- 2번: D의 우선순위가 3.5로 가장 높다.\n- 3번: A의 우선순위는 2.2이다.\n- 4번: C의 우선순위는 1.8로 가장 낮다.\n\n**보충 개념**\nHRN은 긴 작업과 짧은 작업의 불균형을 완화하기 위해 대기시간과 서비스 시간을 함께 고려한다.',
   'HRN 스케줄링', 2, @mock_exam_id, 79, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '프로그래밍 언어 활용' ORDER BY id LIMIT 1), '객체지향 기술 중, 캡슐화에 대한 처리와 가장 거리가 먼 것은?\n\n① 문제 해결에 필요한 속성과 메소드를 하나의 클래스로 묶는다.\n② 인터페이스를 단순화 시킨다.\n③ 실제 구현되는 내용을 외부의 영향으로부터 보호한다.\n④ 여러 하위 객체들이 서로 다른 형태를 가질 수 있도록 한다.', 'MCQ', 4, '정답: 4. 여러 하위 객체들이 서로 다른 형태를 가지는 것은 다형성에 대한 설명이다.\n\n**오답 풀이**\n- 1번: 속성과 메서드를 하나로 묶는 것은 캡슐화이다.\n- 2번: 캡슐화는 외부 인터페이스를 단순화할 수 있다.\n- 3번: 캡슐화는 내부 구현을 보호한다.\n- 4번: 서로 다른 형태로 동작하는 것은 다형성이다.\n\n**보충 개념**\n캡슐화는 데이터와 기능을 하나로 묶고, 외부 접근을 제한해 변경 영향을 줄인다.',
   '캡슐화', 2, @mock_exam_id, 80, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '아래 설명에 해당하는 용어를 고르시오.\n\n**<보기>**\n- 네트워크의 트래픽 전달 동작을 소프트웨어 기반으로 제어/관리하는 접근 방식이다.\n- 네트워크 제어 영역과 포워딩 영역을 분리한다.\n- 네트워크 리소스를 가상화하고 추상화하는 네트워크 인프라에 대한 접근 방식이다.\n\n① SDN\n② MAC\n③ ISDN\n④ ATM', 'MCQ', 1, '정답: 1. 제어 영역과 데이터 전달 영역을 분리해 소프트웨어로 네트워크를 제어하는 기술은 SDN이다.\n\n**오답 풀이**\n- 1번: SDN은 Software Defined Networking의 약자이다.\n- 2번: MAC은 강제 접근 통제 또는 매체 접근 제어 등 다른 의미로 쓰인다.\n- 3번: ISDN은 종합 정보 통신망이다.\n- 4번: ATM은 비동기 전달 모드이다.\n\n**보충 개념**\nSDN은 중앙 제어를 통해 네트워크 구성과 정책 적용을 유연하게 한다.',
   'SDN', 2, @mock_exam_id, 81, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '인터넷상에서 작은 패킷 단위로 나누어 전송되는 정보를 감시하여 유해 트래픽을 차단하고, 중요한 서비스에 대한 우선순위를 부여함으로써 망을 한층 효율적으로 사용할 수 있게 하는 기술은 무엇인가?\n\n① PDF\n② NFT\n③ DPI\n④ API', 'MCQ', 3, '정답: 3. 패킷 내부 콘텐츠까지 분석해 유해 트래픽을 차단하고 트래픽을 제어하는 기술은 DPI이다.\n\n**오답 풀이**\n- 1번: PDF는 문서 형식이다.\n- 2번: NFT는 대체 불가능 토큰이다.\n- 3번: DPI는 Deep Packet Inspection으로 패킷 심층 분석 기술이다.\n- 4번: API는 응용 프로그램 인터페이스이다.\n\n**보충 개념**\nDPI는 네트워크 보안, 트래픽 관리, QoS 정책 적용 등에 활용된다.',
   'DPI', 2, @mock_exam_id, 82, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '아래 설명에 해당하는 도구는 무엇인가?\n\n**<보기>**\n- 호스트 기반으로 파일 시스템 오브젝트들의 변화를 탐지하는 시스템이다.\n- 침입 이후 탐지에 매우 유용할 뿐만 아니라 무결성 입증과 변화 관리 그리고 정책 준수 같은 다른 여러 목적으로도 사용될 수 있다.\n\n① SATAN\n② Klaxon\n③ Watcher\n④ Tripwire', 'MCQ', 4, '정답: 4. 파일 시스템 변경을 탐지하고 무결성을 점검하는 대표 도구는 Tripwire이다.\n\n**오답 풀이**\n- 1번: SATAN은 보안 취약점 분석 도구로 알려져 있다.\n- 2번: Klaxon은 대표적인 파일 무결성 점검 도구로 보기 어렵다.\n- 3번: Watcher는 일반적인 감시 도구 명칭으로 쓰일 수 있으나 정답 도구는 아니다.\n- 4번: Tripwire는 파일 변경 탐지와 무결성 검증에 사용된다.\n\n**보충 개념**\nTripwire는 침입자가 파일을 변경했는지 탐지하는 호스트 기반 침입 탐지에 활용된다.',
   'Tripwire', 2, @mock_exam_id, 83, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '아래 설명에 해당하는 용어는 무엇인가?\n\n**<보기>**\n- 컴퓨터에서 서버의 안정성을 증대시키기 위한 솔루션으로 여러 컴퓨터 시스템을 연결할 수 있다.\n- 각 시스템 간에 공유 디스크를 중심으로 클러스터링으로 엮어지며 다수의 시스템을 동시에 연결한다.\n- 2개 시스템이 각각 업무를 수행함으로써 시스템 장애를 몇 초 만에 복구할 수 있다.\n\n① HACMP\n② renderung\n③ blockchain\n④ RAID', 'MCQ', 1, '정답: 1. 고가용성을 위해 여러 시스템을 클러스터링하는 솔루션은 HACMP이다.\n\n**오답 풀이**\n- 1번: HACMP는 High Availability Cluster Multi-Processing의 의미로 고가용성 클러스터링과 관련된다.\n- 2번: renderung은 해당 설명과 관련된 표준 용어가 아니다.\n- 3번: blockchain은 분산 원장 기술이다.\n- 4번: RAID는 여러 디스크를 묶어 성능이나 안정성을 높이는 저장장치 기술이다.\n\n**보충 개념**\n고가용성 클러스터는 장애 발생 시 서비스를 빠르게 다른 노드로 전환해 중단 시간을 줄인다.',
   '고가용성', 2, @mock_exam_id, 84, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '아래 설명에 해당하는 용어는 무엇인가?\n\n**<보기>**\n- 1990년대의 ‘스노우 크래쉬’ 소설에서 처음 사용된 용어이다.\n- 현실 세계와 같이 사회, 경제, 문화 활동에 대한 상호작용이 이뤄진다.\n- 게임, SNS, 교육, 의료 등 많은 산업에서 활용한다.\n\n① Augmented Reality\n② Metaverse\n③ Mobile Location Service\n④ Hologram', 'MCQ', 2, '정답: 2. 현실과 유사한 상호작용이 이루어지는 가상 세계 개념은 메타버스이다.\n\n**오답 풀이**\n- 1번: Augmented Reality는 현실 환경에 가상 정보를 겹쳐 보여주는 증강현실이다.\n- 2번: Metaverse는 현실과 유사한 사회·경제·문화 활동이 가능한 가상 세계이다.\n- 3번: Mobile Location Service는 모바일 위치 기반 서비스이다.\n- 4번: Hologram은 입체 영상을 기록·재생하는 기술이다.\n\n**보충 개념**\n메타버스는 가상 공간에서 사용자 간 상호작용과 경제 활동이 가능한 플랫폼 개념으로 확장되었다.',
   '메타버스', 1, @mock_exam_id, 85, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중, 사용자의 역할에 기반을 두고 접근을 통제하는 접근 통제 모델은 무엇인가?\n\n① RBAC\n② MAC\n③ DAC\n④ AAC', 'MCQ', 1, '정답: 1. 사용자 역할에 따라 접근 권한을 부여하는 모델은 RBAC이다.\n\n**오답 풀이**\n- 1번: RBAC은 Role-Based Access Control이다.\n- 2번: MAC은 보안 등급에 따라 접근을 통제하는 강제 접근 통제이다.\n- 3번: DAC은 소유자나 사용자 신원에 따라 접근을 통제하는 임의 접근 통제이다.\n- 4번: AAC는 일반적인 대표 접근 통제 모델 명칭으로 보기 어렵다.\n\n**보충 개념**\nRBAC은 조직 내 직무와 역할에 따라 권한을 관리하기 쉬워 대규모 시스템에서 자주 사용된다.',
   '접근 통제', 1, @mock_exam_id, 86, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '전기 및 정보통신기술을 활용하여 전력망을 지능화, 고도화함으로써 고품질의 전력 서비스를 제공하고 에너지 이용 효율을 극대화하는 전력망은?\n\n① 디지털 아카이빙\n② 스마트 그리드\n③ 미디어 빅뱅\n④ 로직 네트워크', 'MCQ', 2, '정답: 2. 전력망에 정보통신기술을 접목해 효율을 높인 전력망은 스마트 그리드이다.\n\n**오답 풀이**\n- 1번: 디지털 아카이빙은 디지털 정보를 장기 보존하는 작업이다.\n- 2번: 스마트 그리드는 전력망을 지능화해 에너지 효율을 높인다.\n- 3번: 미디어 빅뱅은 미디어 환경 변화와 관련된 용어이다.\n- 4번: 로직 네트워크는 해당 설명의 전력망 기술이 아니다.\n\n**보충 개념**\n스마트 그리드는 전력 공급과 소비 정보를 실시간으로 관리해 효율적 에너지 운영을 지원한다.',
   '스마트 그리드', 1, @mock_exam_id, 87, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중, IPv6의 전송 방식에 해당하지 않는 것은?\n\n① 유니 캐스트\n② 멀티 캐스트\n③ 브로드 캐스트\n④ 애니 캐스트', 'MCQ', 3, '정답: 3. IPv6는 브로드캐스트를 사용하지 않고 유니캐스트, 멀티캐스트, 애니캐스트를 사용한다.\n\n**오답 풀이**\n- 1번: 유니캐스트는 IPv6 전송 방식이다.\n- 2번: 멀티캐스트는 IPv6 전송 방식이다.\n- 3번: 브로드캐스트는 IPv6에서 사용하지 않는다.\n- 4번: 애니캐스트는 IPv6 전송 방식이다.\n\n**보충 개념**\nIPv6에서는 브로드캐스트 대신 멀티캐스트를 활용해 불필요한 트래픽을 줄인다.',
   'IPv6', 1, @mock_exam_id, 88, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '사용자로부터 입력되는 값을 기반으로 재요청하는 기능을 이용하여 공격자가 의도한 도메인으로 사용자를 이동시키는 취약점(공격 기법)은 무엇인가?\n\n① Switch Jamming\n② Blue Snarfing\n③ Dictionary Attack\n④ Open Redirect', 'MCQ', 4, '정답: 4. 사용자 입력값을 조작해 악성 도메인으로 이동시키는 공격은 Open Redirect이다.\n\n**오답 풀이**\n- 1번: Switch Jamming은 스위치 환경에서 트래픽을 가로채기 위한 공격과 관련된다.\n- 2번: Blue Snarfing은 블루투스 취약점을 이용한 정보 탈취 공격이다.\n- 3번: Dictionary Attack은 사전 파일을 이용한 비밀번호 대입 공격이다.\n- 4번: Open Redirect는 신뢰된 URL처럼 보이게 하여 악성 사이트로 리다이렉트한다.\n\n**보충 개념**\nOpen Redirect 방지는 리다이렉트 대상 URL 검증과 화이트리스트 방식이 중요하다.',
   'Open Redirect', 2, @mock_exam_id, 89, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중, AES(Advanced Encryption Standard)에 대한 설명과 가장 거리가 먼 것은?\n\n① DES를 대체하는 미국의 표준 대칭키 블록 알고리즘이다.\n② 128bit의 블록 크기와 가변 길이 키(128/192/256)를 가진다.\n③ 키의 길이에 따라 10/12/14 라운드를 진행한다.\n④ 보안성을 강화한 3AES 알고리즘도 존재하지만 최근에는 사용하지 않는다.', 'MCQ', 4, '정답: 4. DES의 대안으로 3DES가 존재하지만 3AES라는 표현은 일반적인 AES 설명과 맞지 않는다.\n\n**오답 풀이**\n- 1번: AES는 DES를 대체하기 위해 표준화된 대칭키 블록 암호이다.\n- 2번: AES는 128비트 블록 크기와 128/192/256비트 키를 사용한다.\n- 3번: 키 길이에 따라 10, 12, 14라운드를 수행한다.\n- 4번: 3AES가 아니라 3DES가 DES의 확장 알고리즘으로 알려져 있다.\n\n**보충 개념**\nAES는 현재 널리 사용되는 대표적인 대칭키 블록 암호 알고리즘이다.',
   'AES', 2, @mock_exam_id, 90, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '소유 기반 인증(Something You Have) 요소에 해당하지 않는 것은 무엇인가?\n\n① 출입 카드\n② 지문 인식\n③ OTP\n④ 토큰', 'MCQ', 2, '정답: 2. 지문 인식은 사용자의 생체 특성을 이용하므로 존재 기반 인증(Something You Are)에 해당한다.\n\n**오답 풀이**\n- 1번: 출입 카드는 소유 기반 인증 요소이다.\n- 2번: 지문 인식은 생체 기반 인증이다.\n- 3번: OTP는 사용자가 소유한 장치나 토큰을 통해 생성되는 인증 요소이다.\n- 4번: 토큰은 소유 기반 인증 요소이다.\n\n**보충 개념**\n인증 요소는 지식 기반, 소유 기반, 존재 기반 등으로 구분할 수 있다.',
   '인증 요소', 1, @mock_exam_id, 91, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '10cm 이내의 거리에서 기가급 초고속 근접 무선통신이 가능한 기술은 무엇인가?\n\n① SDDC\n② Ad-hoc\n③ Zing\n④ RFID', 'MCQ', 3, '정답: 3. 10cm 이내 근거리에서 기가급 데이터 전송이 가능한 초고속 근접 무선통신 기술은 Zing이다.\n\n**오답 풀이**\n- 1번: SDDC는 소프트웨어 정의 데이터센터이다.\n- 2번: Ad-hoc은 고정 기반망 없이 구성되는 임시 네트워크이다.\n- 3번: Zing은 초고속 근접 무선통신 기술이다.\n- 4번: RFID는 전파를 이용한 식별 기술이다.\n\n**보충 개념**\nZing은 매우 짧은 거리에서 대용량 데이터를 빠르게 전송하는 근접 통신 기술로 설명된다.',
   'Zing', 2, @mock_exam_id, 92, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'CSMA/CA 방식에 대한 설명과 가장 거리가 먼 것은?\n\n① 예비 신호 전송을 통해 패킷 충돌을 피하는 방식이다.\n② CSMA 방식에 충돌 검출 기능과 재송신 기능을 추가하였다.\n③ IEEE 802.11 프로토콜을 사용한다.\n④ 사용 중인 채널에 일정한 규칙을 통하여 접근하는 방식이다.', 'MCQ', 2, '정답: 2. CSMA 방식에 충돌 검출 기능과 재송신 기능을 추가한 것은 CSMA/CD에 대한 설명이다.\n\n**오답 풀이**\n- 1번: CSMA/CA는 충돌을 사전에 회피하려는 방식이다.\n- 2번: 충돌 검출은 CSMA/CD의 특징이다.\n- 3번: CSMA/CA는 IEEE 802.11 무선 LAN에서 사용된다.\n- 4번: 채널 사용 여부를 확인하고 규칙에 따라 접근한다.\n\n**보충 개념**\n무선 환경에서는 충돌 검출이 어렵기 때문에 CSMA/CA를 사용해 충돌을 회피한다.',
   'CSMA/CA', 2, @mock_exam_id, 93, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'OSI 7계층 중, 네트워크 계층에 해당하는 장비는 무엇인가?\n\n① 라우터\n② 브릿지\n③ 스위치\n④ 리피터', 'MCQ', 1, '정답: 1. 라우터는 IP 주소를 기반으로 경로를 결정하는 네트워크 계층 장비이다.\n\n**오답 풀이**\n- 1번: 라우터는 네트워크 계층 장비이다.\n- 2번: 브릿지는 데이터링크 계층 장비이다.\n- 3번: 일반적인 스위치는 데이터링크 계층 장비이다.\n- 4번: 리피터는 물리 계층 장비이다.\n\n**보충 개념**\n네트워크 계층은 서로 다른 네트워크 간 경로 선택과 패킷 전달을 담당한다.',
   'OSI 7계층', 1, @mock_exam_id, 94, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'IP나 ICMP의 특성을 악용하여 엄청난 양의 데이터를 한 사이트에 집중적으로 보냄으로써 네트워크의 일부를 불능 상태로 만드는 공격 방법은 무엇인가?\n\n① Blue Jacking\n② LAND Attack\n③ SYN Flooding\n④ Smurf Attack', 'MCQ', 4, '정답: 4. ICMP Echo 요청과 브로드캐스트를 악용해 공격 대상에 대량 응답을 유도하는 공격은 Smurf Attack이다.\n\n**오답 풀이**\n- 1번: Blue Jacking은 블루투스를 이용해 메시지를 보내는 공격이다.\n- 2번: LAND Attack은 출발지와 목적지 주소를 같게 조작하는 공격이다.\n- 3번: SYN Flooding은 TCP 연결 요청을 대량으로 보내는 공격이다.\n- 4번: Smurf Attack은 ICMP와 브로드캐스트를 악용한다.\n\n**보충 개념**\nSmurf Attack은 출발지 IP를 피해자로 위조하여 다수의 응답이 피해자에게 몰리게 한다.',
   'Smurf Attack', 2, @mock_exam_id, 95, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'OSI 7계층 중, 데이터 통신을 위한 양 끝단의 응용 프로세스가 통신을 관리하기 위한 방법을 제공하는 계층은 무엇인가?\n\n① Session Layer\n② Physical Layer\n③ Network Layer\n④ Transport Layer', 'MCQ', 1, '정답: 1. 응용 프로세스 간 대화 제어와 통신 관리를 제공하는 계층은 세션 계층이다.\n\n**오답 풀이**\n- 1번: 세션 계층은 양 끝단 응용 프로세스 간 통신 세션을 관리한다.\n- 2번: 물리 계층은 전기적·물리적 전송을 담당한다.\n- 3번: 네트워크 계층은 경로 설정과 패킷 전달을 담당한다.\n- 4번: 전송 계층은 종단 간 신뢰성 있는 데이터 전달을 담당한다.\n\n**보충 개념**\n세션 계층은 연결 설정, 유지, 종료와 대화 제어를 담당한다.',
   '세션 계층', 1, @mock_exam_id, 96, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), 'IPv4의 헤더 구조 중, 도착한 패킷에 대한 오류 여부를 체크하기 위해 존재하는 요소는 무엇인가?\n\n① TOS\n② Checksum\n③ Time To Live\n④ Version', 'MCQ', 2, '정답: 2. IPv4 헤더의 오류 검출을 위해 사용되는 필드는 Header Checksum이다.\n\n**오답 풀이**\n- 1번: TOS는 서비스 유형을 나타낸다.\n- 2번: Checksum은 헤더 오류 검출에 사용된다.\n- 3번: Time To Live는 패킷 생존 시간을 제한한다.\n- 4번: Version은 IP 프로토콜 버전을 나타낸다.\n\n**보충 개념**\nIPv4 Header Checksum은 헤더의 오류 여부를 확인하기 위한 필드이다.',
   'IPv4 헤더', 1, @mock_exam_id, 97, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '규정된 크기 이상의 ICMP 패킷을 전송하여 DoS를 유발시키거나 과부하로 인한 Crashing, 리부팅 등을 유발하는 공격 방법은 무엇인가?\n\n① Ping of Death\n② Trojan Horse\n③ Sniffing\n④ Brute Force Attack', 'MCQ', 1, '정답: 1. 허용 범위를 초과하는 ICMP 패킷을 보내 시스템 장애를 유발하는 공격은 Ping of Death이다.\n\n**오답 풀이**\n- 1번: Ping of Death는 비정상적으로 큰 ICMP 패킷을 이용한다.\n- 2번: Trojan Horse는 정상 프로그램처럼 위장한 악성 프로그램이다.\n- 3번: Sniffing은 네트워크 패킷을 도청하는 행위이다.\n- 4번: Brute Force Attack은 가능한 모든 조합을 대입하는 공격이다.\n\n**보충 개념**\nPing of Death는 과거 IP 패킷 처리 취약점을 악용한 서비스 거부 공격이다.',
   'Ping of Death', 1, @mock_exam_id, 98, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중, 정보보안의 3요소에 해당하지 않는 것은?\n\n① Confidentiality\n② Authentication\n③ Integrity\n④ Availability', 'MCQ', 2, '정답: 2. 정보보안의 3요소는 기밀성, 무결성, 가용성이며 인증은 포함되지 않는다.\n\n**오답 풀이**\n- 1번: Confidentiality는 기밀성이다.\n- 2번: Authentication은 인증으로, 정보보안 3요소 자체에는 포함되지 않는다.\n- 3번: Integrity는 무결성이다.\n- 4번: Availability는 가용성이다.\n\n**보충 개념**\n정보보안의 3요소는 CIA로 불리며 Confidentiality, Integrity, Availability를 의미한다.',
   '정보보안 3요소', 1, @mock_exam_id, 99, 'NONE', NULL, NOW(6), NOW(6)),
  ((SELECT id FROM subject WHERE name = '정보시스템 구축 관리' ORDER BY id LIMIT 1), '다음 중, 해시 암호화 알고리즘에 해당하는 것은?\n\n① SNEFRU\n② IDEA\n③ SEED\n④ TKIP', 'MCQ', 1, '정답: 1. SNEFRU는 해시 함수 알고리즘에 해당한다.\n\n**오답 풀이**\n- 1번: SNEFRU는 해시 함수로 분류된다.\n- 2번: IDEA는 대칭키 블록 암호 알고리즘이다.\n- 3번: SEED는 국내에서 개발된 블록 암호 알고리즘이다.\n- 4번: TKIP는 무선 보안에서 사용된 임시 키 무결성 프로토콜이다.\n\n**보충 개념**\n대표 해시 알고리즘에는 MD5, SHA 계열, SNEFRU 등이 있다.',
   '해시 알고리즘', 1, @mock_exam_id, 100, 'NONE', NULL, NOW(6), NOW(6))
;